// ─── STEP 2: ENSURE RAW DATA SHEET EXISTS ────────────────────────────────────
// User pastes in pre-formatted 26-column data with its own headers.
// We just ensure the sheet exists and freeze the header row.
export async function createDataSheet() {
  await Excel.run(async (context) => {
    const sheets = context.workbook.worksheets;
    sheets.load("items/name");
    await context.sync();

    const exists = sheets.items.some((s) => s.name === "Sheet1");
    let sheet;
    if (exists) {
      sheet = sheets.getItem("Sheet1");
    } else {
      sheet = sheets.add("Sheet1");
    }

    // Style header row (row 1) if data is present
    const usedRange = sheet.getUsedRange();
    usedRange.load("rowCount");
    await context.sync();

    if (usedRange.rowCount >= 1) {
      const headerRange = sheet.getRange("1:1");
      headerRange.format.font.bold = true;
      headerRange.format.fill.color = "#1F3864";
      headerRange.format.font.color = "white";
    }

    sheet.freezePanes.freezeRows(1);
    sheet.activate();

    await context.sync();
  });
}

// ─── PIVOT TIME FILTER HELPER ────────────────────────────────────────────────
// ─── SHARED: PROFESSIONAL PIVOT SHEET WRITER (Handsontable style) ────────────

async function writeProfessionalPivot(context, sheetName, role, rawData) {
  const filtered = rawData.filter((r) => r.role === role);

  // ── Extract unique weeks per year from ALL rawData (not role-filtered)
  // This ensures every week present in Sheet1 appears in the filter dropdown,
  // regardless of role casing or whether Mech BASE data exists for that week.
  const allDates = rawData
    .map((r) => r.ppeDate)
    .filter(Boolean)
    .sort((a, b) => a - b);
  const weeks25 = [
    ...new Set(allDates.filter((d) => d.getFullYear() !== 2026).map((d) => formatDate(d))),
  ];
  const weeks26 = [
    ...new Set(allDates.filter((d) => d.getFullYear() === 2026).map((d) => formatDate(d))),
  ];

  // Validate current selections (reset if value no longer in data)
  if (_pivotWeek25 && !weeks25.includes(_pivotWeek25)) _pivotWeek25 = "";
  if (_pivotWeek26 && !weeks26.includes(_pivotWeek26)) _pivotWeek26 = "";

  // Default to latest week if not set
  if (!_pivotWeek25 && weeks25.length > 0) _pivotWeek25 = weeks25[weeks25.length - 1];
  if (!_pivotWeek26 && weeks26.length > 0) _pivotWeek26 = weeks26[weeks26.length - 1];

  // ── Group by Region/District with independent year filtering ────────────────
  // 2025 data: filter by selected 2025 week (if set)
  // 2026 data: filter by selected 2026 week (if set)
  const regionMap = {};
  for (const r of filtered) {
    const key = r.region || "(No Region)";
    if (!regionMap[key])
      regionMap[key] = {
        region: key,
        st25: 0,
        ot25: 0,
        dt25: 0,
        stPay25: 0,
        otPay25: 0,
        dtPay25: 0,
        st26: 0,
        ot26: 0,
        dt26: 0,
        stPay26: 0,
        otPay26: 0,
        dtPay26: 0,
      };
    const year = r.ppeDate ? r.ppeDate.getFullYear() : 2025;
    const weekStr = r.ppeDate ? formatDate(r.ppeDate) : "";
    if (year === 2026) {
      if (_pivotWeek26 && weekStr !== _pivotWeek26) continue;
      regionMap[key].st26 += r.st;
      regionMap[key].ot26 += r.ot;
      regionMap[key].dt26 += r.dt;
      regionMap[key].stPay26 += r.stPay;
      regionMap[key].otPay26 += r.otPay;
      regionMap[key].dtPay26 += r.dtPay;
    } else {
      if (_pivotWeek25 && weekStr !== _pivotWeek25) continue;
      regionMap[key].st25 += r.st;
      regionMap[key].ot25 += r.ot;
      regionMap[key].dt25 += r.dt;
      regionMap[key].stPay25 += r.stPay;
      regionMap[key].otPay25 += r.otPay;
      regionMap[key].dtPay25 += r.dtPay;
    }
  }
  for (const code of Object.keys(REGION_NAMES)) {
    if (!regionMap[code]) {
      regionMap[code] = {
        region: code,
        st25: 0, ot25: 0, dt25: 0, stPay25: 0, otPay25: 0, dtPay25: 0,
        st26: 0, ot26: 0, dt26: 0, stPay26: 0, otPay26: 0, dtPay26: 0,
      };
    }
  }
  const regions = Object.values(regionMap).sort((a, b) => a.region.localeCompare(b.region));

  const totals = regions.reduce(
    (acc, g) => ({
      st25: acc.st25 + g.st25,
      ot25: acc.ot25 + g.ot25,
      dt25: acc.dt25 + g.dt25,
      st26: acc.st26 + g.st26,
      ot26: acc.ot26 + g.ot26,
      dt26: acc.dt26 + g.dt26,
      stPay25: acc.stPay25 + g.stPay25,
      otPay25: acc.otPay25 + g.otPay25,
      dtPay25: acc.dtPay25 + g.dtPay25,
      stPay26: acc.stPay26 + g.stPay26,
      otPay26: acc.otPay26 + g.otPay26,
      dtPay26: acc.dtPay26 + g.dtPay26,
    }),
    {
      st25: 0,
      ot25: 0,
      dt25: 0,
      st26: 0,
      ot26: 0,
      dt26: 0,
      stPay25: 0,
      otPay25: 0,
      dtPay25: 0,
      stPay26: 0,
      otPay26: 0,
      dtPay26: 0,
    }
  );

  // Ensure sheet exists and clear
  const sheets = context.workbook.worksheets;
  sheets.load("items/name");
  await context.sync();

  let sheet;
  const exists = sheets.items.some((s) => s.name === sheetName);
  if (exists) {
    sheet = sheets.getItem(sheetName);
    sheet.getUsedRange().clear();
  } else {
    sheet = sheets.add(sheetName);
  }

  const roleLabel = "MECHANIC BASE";

  // ── Color palette ─────────────────────────────────────────────────────────────
  const TITLE_BG = "#153d64"; // deep navy blue title
  const SUB_BG = "#BAE6FD"; // sky-200 — section header background
  const SUB_TEXT = "#0C4A6E"; // sky-950 — section header text
  const HDR_FILL = "#1E293B"; // slate-800 — region col headers
  const BODY_TEXT = "#0F172A"; // slate-950 — body text
  const BORDER_CLR = "#f7fcff"; // very light blue-white — borders
  const ALT_FILL = "#F0F9FF"; // sky-50 — blue-tinted alternating rows
  const YR25 = "#475569"; // slate-600 — 2025 (muted, historical)
  const YR26 = "#0369A1"; // sky-700 — 2026 (active, prominent)
  const YR_DELTA = "#0E7490"; // cyan-700 — change indicator
  const KV_TEXT = "#FFFFFF"; // white — inverted totals text
  const KV_FILL = "#153d64"; // deep navy blue — inverted totals background

  // Column layout (A:W = 23 cols):
  // Hours: A=RR/DD | B-D=2025 ST/OT/DT | E-G=2026 ST/OT/DT | H-J=△ST/OT/DT | K=△Total Hrs
  // L = separator
  // Pay:   M=RR/DD | N-P=2025 Pay | Q-S=2026 Pay | T-V=△ST/OT/DT Pay | W=△Total Amt

  // Border helper
  const setBorders = (range, color) => {
    const bc = color || BORDER_CLR;
    const b = range.format.borders;
    for (const edge of ["EdgeTop", "EdgeBottom", "EdgeLeft", "EdgeRight"]) {
      b.getItem(edge).style = Excel.BorderLineStyle.thin;
      b.getItem(edge).color = bc;
    }
    try {
      b.getItem("InsideHorizontal").style = Excel.BorderLineStyle.thin;
      b.getItem("InsideHorizontal").color = bc;
      b.getItem("InsideVertical").style = Excel.BorderLineStyle.thin;
      b.getItem("InsideVertical").color = bc;
    } catch (_) {
      /* single-cell ranges don't have inside borders */
    }
  };

  const setOuterBorder = (range, color) => {
    const b = range.format.borders;
    for (const edge of ["EdgeTop", "EdgeBottom", "EdgeLeft", "EdgeRight"]) {
      b.getItem(edge).style = Excel.BorderLineStyle.medium;
      b.getItem(edge).color = color || "#0C4A6E";
    }
  };

  // ── Row 1: Title ──────────────────────────────────────────────────────────────
  const titleRange = sheet.getRange("A1:W1");
  titleRange.merge(false);
  sheet.getRange("A1").values = [[`${roleLabel} OVERTIME REPORT`]];
  sheet.getRange("A1").format.font.bold = true;
  sheet.getRange("A1").format.font.size = 14;
  sheet.getRange("A1").format.font.color = "white";
  sheet.getRange("A1").format.font.name = "Segoe UI";
  titleRange.format.fill.color = TITLE_BG;
  titleRange.format.horizontalAlignment = Excel.HorizontalAlignment.center;
  titleRange.format.verticalAlignment = Excel.VerticalAlignment.center;
  titleRange.format.rowHeight = 34;

  // ── Row 2: Week Filter Bar — vivid sky-500 accent strip ───────────────────────
  const row2All = sheet.getRange("A2:W2");
  row2All.format.fill.color = "#0EA5E9"; // sky-500 — full accent, impossible to miss
  row2All.format.rowHeight = 36;
  row2All.format.verticalAlignment = Excel.VerticalAlignment.center;

  // A2: "2025 WEEK" label — white on sky-500
  const a2 = sheet.getRange("A2");
  a2.values = [["2025 WEEK \u229E"]];
  a2.format.font.bold = true;
  a2.format.font.size = 10;
  a2.format.font.color = "#FFFFFF";
  a2.format.font.name = "Segoe UI";
  a2.format.horizontalAlignment = Excel.HorizontalAlignment.center;

  // B2: 2025 week dropdown button — white pill, navy border
  const b2 = sheet.getRange("B2");
  b2.dataValidation.clear();
  if (weeks25.length > 0) {
    const xRange = sheet.getRange(`X1:X${weeks25.length}`);
    xRange.numberFormat = weeks25.map(() => ["@"]);
    xRange.values = weeks25.map((v) => [v]);
    b2.dataValidation.rule = {
      list: { inCellDropDown: true, source: `=$X$1:$X$${weeks25.length}` },
    };
    b2.numberFormat = [["@"]];
    b2.values = [[_pivotWeek25 || weeks25[weeks25.length - 1]]];
  } else {
    b2.values = [["No data"]];
  }
  b2.format.font.size = 11;
  b2.format.font.name = "Segoe UI";
  b2.format.font.bold = true;
  b2.format.font.color = "#0C4A6E";
  b2.format.fill.color = "#FFFFFF";
  b2.format.horizontalAlignment = Excel.HorizontalAlignment.center;
  for (const edge of ["EdgeTop", "EdgeBottom", "EdgeLeft", "EdgeRight"]) {
    b2.format.borders.getItem(edge).style = Excel.BorderLineStyle.medium;
    b2.format.borders.getItem(edge).color = "#0C4A6E";
  }

  // C2: spacer
  sheet.getRange("C2").format.horizontalAlignment = Excel.HorizontalAlignment.center;

  // D2: "2026 WEEK" label — white on sky-500
  const d2 = sheet.getRange("D2");
  d2.values = [["2026 WEEK \u229E"]];
  d2.format.font.bold = true;
  d2.format.font.size = 10;
  d2.format.font.color = "#FFFFFF";
  d2.format.font.name = "Segoe UI";
  d2.format.horizontalAlignment = Excel.HorizontalAlignment.center;

  // E2: 2026 week dropdown button — white pill, navy border
  const e2 = sheet.getRange("E2");
  e2.dataValidation.clear();
  if (weeks26.length > 0) {
    const yRange = sheet.getRange(`Y1:Y${weeks26.length}`);
    yRange.numberFormat = weeks26.map(() => ["@"]);
    yRange.values = weeks26.map((v) => [v]);
    e2.dataValidation.rule = {
      list: { inCellDropDown: true, source: `=$Y$1:$Y$${weeks26.length}` },
    };
    e2.numberFormat = [["@"]];
    e2.values = [[_pivotWeek26 || weeks26[weeks26.length - 1]]];
  } else {
    e2.values = [["No data"]];
  }
  e2.format.font.size = 11;
  e2.format.font.name = "Segoe UI";
  e2.format.font.bold = true;
  e2.format.font.color = "#0C4A6E";
  e2.format.fill.color = "#FFFFFF";
  e2.format.horizontalAlignment = Excel.HorizontalAlignment.center;
  for (const edge of ["EdgeTop", "EdgeBottom", "EdgeLeft", "EdgeRight"]) {
    e2.format.borders.getItem(edge).style = Excel.BorderLineStyle.medium;
    e2.format.borders.getItem(edge).color = "#0C4A6E";
  }

  // F2: identity label
  const f2 = sheet.getRange("F2");
  f2.values = [["\u25BC WEEK FILTER"]];
  f2.format.font.bold = true;
  f2.format.font.size = 9;
  f2.format.font.color = "#FFFFFF";
  f2.format.font.name = "Segoe UI";
  f2.format.font.italic = true;
  f2.format.horizontalAlignment = Excel.HorizontalAlignment.left;

  // H2:O2: Period badge
  const periodRange = sheet.getRange("H2:O2");
  periodRange.merge(false);
  const periodLabel = `${_pivotWeek25 || "All 2025"}  \u25B6  ${_pivotWeek26 || "All 2026"}`;
  sheet.getRange("H2").values = [[periodLabel]];
  sheet.getRange("H2").format.font.size = 10;
  sheet.getRange("H2").format.font.italic = true;
  sheet.getRange("H2").format.font.bold = true;
  sheet.getRange("H2").format.font.color = "#FFFFFF";
  sheet.getRange("H2").format.font.name = "Segoe UI";
  sheet.getRange("H2").format.fill.color = "#0C4A6E";
  periodRange.format.horizontalAlignment = Excel.HorizontalAlignment.center;

  // ── Row 3: Divider — navy to transition from bright bar back to content ─────────
  sheet.getRange("A3:W3").format.rowHeight = 4;
  sheet.getRange("A3:W3").format.fill.color = "#153d64"; // navy separator (flipped from accent)

  // ── Row 4: Sub-section headers ────────────────────────────────────────────────
  const styleSubHdr = (range, text, cell) => {
    range.merge(false);
    sheet.getRange(cell).values = [[text]];
    sheet.getRange(cell).format.font.bold = true;
    sheet.getRange(cell).format.font.size = 12;
    sheet.getRange(cell).format.font.color = SUB_TEXT;
    sheet.getRange(cell).format.font.name = "Segoe UI";
    range.format.fill.color = SUB_BG;
    range.format.horizontalAlignment = Excel.HorizontalAlignment.center;
    range.format.verticalAlignment = Excel.VerticalAlignment.center;
  };
  styleSubHdr(sheet.getRange("A4:K4"), "HOURS BREAKDOWN BY REGION", "A4");
  styleSubHdr(sheet.getRange("M4:W4"), "PAY BREAKDOWN BY REGION", "M4");

  // ── Row 5: Year group headers ─────────────────────────────────────────────────
  const styleYrHdr = (mergeRange, cell, label, bg) => {
    mergeRange.merge(false);
    sheet.getRange(cell).values = [[label]];
    mergeRange.format.font.bold = true;
    mergeRange.format.font.size = 12;
    mergeRange.format.font.color = "white";
    mergeRange.format.font.name = "Segoe UI";
    mergeRange.format.fill.color = bg;
    mergeRange.format.horizontalAlignment = Excel.HorizontalAlignment.center;
    mergeRange.format.verticalAlignment = Excel.VerticalAlignment.center;
  };

  // Hours side
  sheet.getRange("A5").format.fill.color = HDR_FILL;
  styleYrHdr(sheet.getRange("B5:D5"), "B5", "2025", YR25);
  styleYrHdr(sheet.getRange("E5:G5"), "E5", "2026", YR26);
  styleYrHdr(sheet.getRange("H5:K5"), "H5", "\u25B3 Change", YR_DELTA);

  // Pay side
  sheet.getRange("M5").format.fill.color = HDR_FILL;
  styleYrHdr(sheet.getRange("N5:P5"), "N5", "2025", YR25);
  styleYrHdr(sheet.getRange("Q5:S5"), "Q5", "2026", YR26);
  styleYrHdr(sheet.getRange("T5:W5"), "T5", "\u25B3 Change", YR_DELTA);

  // ── Row 6: Column headers ─────────────────────────────────────────────────────
  const styleColHdr = (range, label, bg) => {
    range.values = typeof label === "string" ? [[label]] : [label];
    range.format.font.bold = true;
    range.format.font.size = 9;
    range.format.font.color = "white";
    range.format.font.name = "Segoe UI";
    range.format.fill.color = bg;
    range.format.horizontalAlignment = Excel.HorizontalAlignment.center;
    range.format.verticalAlignment = Excel.VerticalAlignment.center;
  };

  // Hours col headers
  styleColHdr(sheet.getRange("A6"), "RR/DD", HDR_FILL);
  styleColHdr(sheet.getRange("B6:D6"), ["Total ST Hrs", "Total OT Hrs", "Total DT Hrs"], YR25);
  styleColHdr(sheet.getRange("E6:G6"), ["Total ST Hrs", "Total OT Hrs", "Total DT Hrs"], YR26);
  styleColHdr(
    sheet.getRange("H6:J6"),
    ["\u25B3 ST Hrs", "\u25B3 OT Hrs", "\u25B3 DT Hrs"],
    YR_DELTA
  );
  styleColHdr(sheet.getRange("K6"), "\u25B3 Total Hrs", YR_DELTA);

  // Pay col headers
  styleColHdr(sheet.getRange("M6"), "RR/DD", HDR_FILL);
  styleColHdr(sheet.getRange("N6:P6"), ["Total ST Amt", "Total OT Amt", "Total DT Amt"], YR25);
  styleColHdr(sheet.getRange("Q6:S6"), ["Total ST Amt", "Total OT Amt", "Total DT Amt"], YR26);
  styleColHdr(
    sheet.getRange("T6:V6"),
    ["\u25B3 ST Amt", "\u25B3 OT Amt", "\u25B3 DT Amt"],
    YR_DELTA
  );
  styleColHdr(sheet.getRange("W6"), "\u25B3 Total Amt", YR_DELTA);

  // ── Data Rows ─────────────────────────────────────────────────────────────────
  if (regions.length > 0) {
    const dataStart = 7;
    const dataEnd = 6 + regions.length;

    // Formatting helpers — ALL return strings, no raw numbers
    const addCommas = (n) => String(n).replace(/\B(?=(\d{3})+(?!\d))/g, ",");
    const toInt = (v) => Math.round(Number(v) || 0);
    const fmtHrs = (v) => {
      const n = toInt(v);
      return n < 0 ? `(${addCommas(Math.abs(n))})` : addCommas(n);
    };
    const fmtPay = (v) => {
      const n = toInt(v);
      return n < 0 ? `($${addCommas(Math.abs(n))})` : `$${addCommas(n)}`;
    };
    const fmtDeltaH = (v) => {
      const n = toInt(v);
      return n > 0 ? addCommas(n) : n < 0 ? `(${addCommas(Math.abs(n))})` : "-";
    };
    const fmtDeltaP = (v) => {
      const n = toInt(v);
      return n > 0 ? `$${addCommas(n)}` : n < 0 ? `($${addCommas(Math.abs(n))})` : "-";
    };

    const hoursRows = regions.map((g) => [
      g.region,
      fmtHrs(g.st25),
      fmtHrs(g.ot25),
      fmtHrs(g.dt25),
      fmtHrs(g.st26),
      fmtHrs(g.ot26),
      fmtHrs(g.dt26),
      fmtDeltaH(g.st26 - g.st25),
      fmtDeltaH(g.ot26 - g.ot25),
      fmtDeltaH(g.dt26 - g.dt25),
      fmtDeltaH(g.st26 + g.ot26 + g.dt26 - (g.st25 + g.ot25 + g.dt25)),
    ]);
    const payRows = regions.map((g) => [
      g.region,
      fmtPay(g.stPay25),
      fmtPay(g.otPay25),
      fmtPay(g.dtPay25),
      fmtPay(g.stPay26),
      fmtPay(g.otPay26),
      fmtPay(g.dtPay26),
      fmtDeltaP(g.stPay26 - g.stPay25),
      fmtDeltaP(g.otPay26 - g.otPay25),
      fmtDeltaP(g.dtPay26 - g.dtPay25),
      fmtDeltaP(g.stPay26 + g.otPay26 + g.dtPay26 - (g.stPay25 + g.otPay25 + g.dtPay25)),
    ]);

    // Format all data as text to preserve parentheses and leading zeros
    const textFmt = hoursRows.map(() => ["@", "@", "@", "@", "@", "@", "@", "@", "@", "@", "@"]);
    sheet.getRange(`A${dataStart}:K${dataEnd}`).numberFormat = textFmt;
    sheet.getRange(`M${dataStart}:W${dataEnd}`).numberFormat = textFmt;

    sheet.getRange(`A${dataStart}:K${dataEnd}`).values = hoursRows;
    sheet.getRange(`M${dataStart}:W${dataEnd}`).values = payRows;

    // Delta constants
    const DELTA_BG_POS = "#FFF1F2"; // rose-50  (increase = bad for OT cost)
    const DELTA_BG_NEG = "#F0FDF4"; // green-50 (decrease = good)
    const DELTA_BG_ZERO = "#F0F9FF"; // sky-50   (no change)
    const DELTA_FG_POS = "#E11D48"; // rose-600 text
    const DELTA_FG_NEG = "#15803D"; // green-700 text
    const DELTA_FG_ZERO = "#0369A1"; // sky-700 text
    const hoursDeltaCols = ["H", "I", "J", "K"];
    const payDeltaCols = ["T", "U", "V", "W"];

    // Helper: style a delta cell (colors only — values already formatted in arrays)
    const styleDelta = (cell, val) => {
      cell.format.font.bold = true;
      if (val > 0) {
        cell.format.fill.color = DELTA_BG_POS;
        cell.format.font.color = DELTA_FG_POS;
      } else if (val < 0) {
        cell.format.fill.color = DELTA_BG_NEG;
        cell.format.font.color = DELTA_FG_NEG;
      } else {
        cell.format.fill.color = DELTA_BG_ZERO;
        cell.format.font.color = DELTA_FG_ZERO;
      }
    };

    // Single loop: alternating rows + delta coloring
    for (let i = 0; i < regions.length; i++) {
      const bg = i % 2 === 0 ? "#FFFFFF" : ALT_FILL;
      const row = dataStart + i;
      const r = regions[i];
      const hRow = sheet.getRange(`A${row}:K${row}`);
      const pRow = sheet.getRange(`M${row}:W${row}`);
      hRow.format.fill.color = bg;
      pRow.format.fill.color = bg;
      hRow.format.font.color = BODY_TEXT;
      pRow.format.font.color = BODY_TEXT;
      hRow.format.font.size = 10;
      pRow.format.font.size = 10;
      hRow.format.font.name = "Segoe UI";
      pRow.format.font.name = "Segoe UI";
      setBorders(hRow);
      setBorders(pRow);

      // Delta columns — hours
      const hDeltas = [
        r.st26 - r.st25,
        r.ot26 - r.ot25,
        r.dt26 - r.dt25,
        r.st26 + r.ot26 + r.dt26 - (r.st25 + r.ot25 + r.dt25),
      ];
      hoursDeltaCols.forEach((col, idx) => {
        styleDelta(sheet.getRange(`${col}${row}`), hDeltas[idx]);
      });
      // Delta columns — pay
      const pDeltas = [
        r.stPay26 - r.stPay25,
        r.otPay26 - r.otPay25,
        r.dtPay26 - r.dtPay25,
        r.stPay26 + r.otPay26 + r.dtPay26 - (r.stPay25 + r.otPay25 + r.dtPay25),
      ];
      payDeltaCols.forEach((col, idx) => {
        styleDelta(sheet.getRange(`${col}${row}`), pDeltas[idx]);
      });
    }

    // ── Region column accent — highlight axis column with sky-100 + bold sky text ──
    for (let i = 0; i < regions.length; i++) {
      const row = dataStart + i;
      const aCell = sheet.getRange(`A${row}`);
      const mCell = sheet.getRange(`M${row}`);
      aCell.format.fill.color = "#E0F2FE"; // sky-100
      aCell.format.font.color = "#0369A1"; // sky-700
      aCell.format.font.bold = true;
      mCell.format.fill.color = "#E0F2FE";
      mCell.format.font.color = "#0369A1";
      mCell.format.font.bold = true;
    }

    // ── Totals Row ───────────────────────────────────────────────────────────
    const totalRow = dataEnd + 1;

    const writeTotals = (range, vals) => {
      range.values = [vals];
      range.format.font.bold = true;
      range.format.font.size = 10;
      range.format.font.color = KV_TEXT;
      range.format.font.name = "Segoe UI";
      range.format.fill.color = KV_FILL;
      setBorders(range, BORDER_CLR);
    };

    // Format totals row as text
    sheet.getRange(`A${totalRow}:K${totalRow}`).numberFormat = [
      ["@", "@", "@", "@", "@", "@", "@", "@", "@", "@", "@"],
    ];
    sheet.getRange(`M${totalRow}:W${totalRow}`).numberFormat = [
      ["@", "@", "@", "@", "@", "@", "@", "@", "@", "@", "@"],
    ];

    writeTotals(sheet.getRange(`A${totalRow}:K${totalRow}`), [
      "TOTAL",
      fmtHrs(totals.st25),
      fmtHrs(totals.ot25),
      fmtHrs(totals.dt25),
      fmtHrs(totals.st26),
      fmtHrs(totals.ot26),
      fmtHrs(totals.dt26),
      fmtDeltaH(totals.st26 - totals.st25),
      fmtDeltaH(totals.ot26 - totals.ot25),
      fmtDeltaH(totals.dt26 - totals.dt25),
      fmtDeltaH(
        totals.st26 + totals.ot26 + totals.dt26 - (totals.st25 + totals.ot25 + totals.dt25)
      ),
    ]);
    writeTotals(sheet.getRange(`M${totalRow}:W${totalRow}`), [
      "TOTAL",
      fmtPay(totals.stPay25),
      fmtPay(totals.otPay25),
      fmtPay(totals.dtPay25),
      fmtPay(totals.stPay26),
      fmtPay(totals.otPay26),
      fmtPay(totals.dtPay26),
      fmtDeltaP(totals.stPay26 - totals.stPay25),
      fmtDeltaP(totals.otPay26 - totals.otPay25),
      fmtDeltaP(totals.dtPay26 - totals.dtPay25),
      fmtDeltaP(
        totals.stPay26 +
          totals.otPay26 +
          totals.dtPay26 -
          (totals.stPay25 + totals.otPay25 + totals.dtPay25)
      ),
    ]);

    // Thick dark outer border around both table sections
    setOuterBorder(sheet.getRange(`A1:K${totalRow}`));
    setOuterBorder(sheet.getRange(`M1:W${totalRow}`));
    // Thick top border on totals row to separate from data
    for (const edge of ["EdgeTop"]) {
      sheet.getRange(`A${totalRow}:K${totalRow}`).format.borders.getItem(edge).style =
        Excel.BorderLineStyle.medium;
      sheet.getRange(`A${totalRow}:K${totalRow}`).format.borders.getItem(edge).color = "#0C4A6E";
      sheet.getRange(`M${totalRow}:W${totalRow}`).format.borders.getItem(edge).style =
        Excel.BorderLineStyle.medium;
      sheet.getRange(`M${totalRow}:W${totalRow}`).format.borders.getItem(edge).color = "#0C4A6E";
    }

    // ── Separator column (L) from row 2 down — no fill ──────────────────────────
    sheet.getRange(`L2:L${totalRow}`).format.fill.color = "#FFFFFF";
  } else {
    const noData = sheet.getRange("A7:W7");
    noData.merge(false);
    sheet.getRange("A7").values = [["No data found for this role."]];
    sheet.getRange("A7").format.font.italic = true;
    sheet.getRange("A7").format.font.color = "#999999";
  }

  // ── Column Widths ─────────────────────────────────────────────────────────────
  // Hours table — A:K use Excel char units (* 5.695 → points)
  sheet.getRange("A:A").format.columnWidth = 14 * 5.695; // 79.73pt ≈ 14 char units
  sheet.getRange("B:K").format.columnWidth = 56;
  // Separator column (L) — narrow gap
  sheet.getRange("L:L").format.columnWidth = 8;
  // Pay table (M:W) — width 14 (Excel char widths ≈ 77pt)
  sheet.getRange("M:W").format.columnWidth = 77;
  sheet.getRange("X:X").columnHidden = true; // 2025 week options (hidden)
  sheet.getRange("Y:Y").columnHidden = true; // 2026 week options (hidden)

  // ── Vertical alignment ────────────────────────────────────────────────────────
  sheet.getUsedRange().format.verticalAlignment = Excel.VerticalAlignment.center;

  // ── Horizontal alignment ──────────────────────────────────────────────────────
  sheet.getRange("A:A").format.horizontalAlignment = Excel.HorizontalAlignment.center;
  sheet.getRange("M:M").format.horizontalAlignment = Excel.HorizontalAlignment.center;
  sheet.getRange("B:K").format.horizontalAlignment = Excel.HorizontalAlignment.right;
  sheet.getRange("N:W").format.horizontalAlignment = Excel.HorizontalAlignment.right;

  // Re-center merged header rows
  sheet.getRange("A1:W1").format.horizontalAlignment = Excel.HorizontalAlignment.center;
  sheet.getRange("H2:O2").format.horizontalAlignment = Excel.HorizontalAlignment.center;
  sheet.getRange("A4:K4").format.horizontalAlignment = Excel.HorizontalAlignment.center;
  sheet.getRange("M4:W4").format.horizontalAlignment = Excel.HorizontalAlignment.center;
  sheet.getRange("B5:D5").format.horizontalAlignment = Excel.HorizontalAlignment.center;
  sheet.getRange("E5:G5").format.horizontalAlignment = Excel.HorizontalAlignment.center;
  sheet.getRange("H5:K5").format.horizontalAlignment = Excel.HorizontalAlignment.center;
  sheet.getRange("N5:P5").format.horizontalAlignment = Excel.HorizontalAlignment.center;
  sheet.getRange("Q5:S5").format.horizontalAlignment = Excel.HorizontalAlignment.center;
  sheet.getRange("T5:W5").format.horizontalAlignment = Excel.HorizontalAlignment.center;

  // ── Autofit all rows, then re-apply structural heights ──────────────────────
  sheet.getUsedRange().format.autofitRows();
  titleRange.format.rowHeight = 34;
  row2All.format.rowHeight = 36;
  sheet.getRange("A3:W3").format.rowHeight = 4;

  sheet.tabColor = TITLE_BG;
  sheet.freezePanes.freezeRows(6);

  await context.sync();
}

// ─── PIVOT FILTER CHANGE HANDLER ─────────────────────────────────────────────
async function handlePivotFilterChange(args) {
  if (_pivotFilterBusy > 0) return;
  _pivotFilterBusy++;

  let needsRebuild = false;
  try {
    await Excel.run(async (context) => {
      const pivotSheet = context.workbook.worksheets.getItem("MechanicBASE_Pivot");
      const b2 = pivotSheet.getRange("B2");
      const e2 = pivotSheet.getRange("E2");
      b2.load("values");
      e2.load("values");
      await context.sync();

      const addr = (args.address || "").replace(/^[^!]+!/, "").replace(/\$/g, "").toUpperCase();
      const newWeek25 = parseWeekValue(b2.values[0][0]);
      const newWeek26 = parseWeekValue(e2.values[0][0]);

      if (addr === "B2" && newWeek25 !== _pivotWeek25 && newWeek25 !== "No data") {
        _pivotWeek25 = newWeek25;
        needsRebuild = true;
      }
      if (addr === "E2" && newWeek26 !== _pivotWeek26 && newWeek26 !== "No data") {
        _pivotWeek26 = newWeek26;
        needsRebuild = true;
      }
    });

    if (needsRebuild) {
      await buildMechanicBasePivot(_allData && _allData.length > 0 ? _allData : null);
    }
  } finally {
    _pivotFilterBusy--;
  }
}

// ─── STEP 3: BUILD MECHANIC BASE PIVOT ───────────────────────────────────────
export async function buildMechanicBasePivot(rawData) {
  _pivotFilterBusy++;
  try {
    await Excel.run(async (context) => {
      const data = rawData || (await readRawData(context));
      await writeProfessionalPivot(context, "MechanicBASE_Pivot", ROLE_MECH_BASE, data);
      // Register pivot filter event handler (once per session)
      if (!_pivotEventRegistered) {
        const pivotSheet = context.workbook.worksheets.getItem("MechanicBASE_Pivot");
        pivotSheet.onChanged.add(handlePivotFilterChange);
        _pivotEventRegistered = true;
        await context.sync();
      }
    });
  } finally {
    _pivotFilterBusy--;
  }
}

// ─── TOTAL WKS IN MONTH: WEEK PAIR BUILDER ──────────────────────────────────
function buildMonthWeekPairs(month, data) {
  const monthIdx = MONTH_NAMES.indexOf(month);
  const base = data.filter((r) => r.role === ROLE_MECH_BASE);

  // Build sets of PPE timestamps that exist in data for each year
  const dataSet25 = new Set(
    base
      .filter((r) => r.ppeDate && r.ppeDate.getFullYear() !== 2026 && r.ppeDate.getMonth() === monthIdx)
      .map((r) => r.ppeDate.getTime())
  );
  const dataSet26 = new Set(
    base
      .filter((r) => r.ppeDate && r.ppeDate.getFullYear() === 2026 && r.ppeDate.getMonth() === monthIdx)
      .map((r) => r.ppeDate.getTime())
  );

  // All calendar Saturdays for the month in each year (sorted ascending)
  const sats25 = getSaturdaysInMonth(2025, monthIdx);
  const sats26 = getSaturdaysInMonth(2026, monthIdx);

  // Align from the END so that the last Saturday of each year pairs together.
  // When one year has more Saturdays (e.g. Mar 2025 has 5, Mar 2026 has 4),
  // the extra at the front is dropped — its data still appears in the summary.
  const minLen = Math.min(sats25.length, sats26.length);
  const paired25 = sats25.slice(sats25.length - minLen);
  const paired26 = sats26.slice(sats26.length - minLen);

  const pairs = [];
  for (let i = 0; i < minLen; i++) {
    pairs.push({
      index: i,
      date25: paired25[i],
      date26: paired26[i],
      label25: formatDate(paired25[i]),
      label26: formatDate(paired26[i]),
      hasData25: dataSet25.has(paired25[i].getTime()),
      hasData26: dataSet26.has(paired26[i].getTime()),
    });
  }
  return pairs;
}

// ─── TOTAL WKS IN MONTH: REGION AGGREGATOR ──────────────────────────────────
function aggregateByRegionForMonth(filtered, week25, week26, monthIdx) {
  const regionMap = {};
  for (const r of filtered) {
    if (!r.ppeDate || r.ppeDate.getMonth() !== monthIdx) continue;
    const key = r.region || "(No Region)";
    if (!regionMap[key])
      regionMap[key] = {
        region: key,
        st25: 0, ot25: 0, dt25: 0, stPay25: 0, otPay25: 0, dtPay25: 0, otDtAmt25: 0,
        st26: 0, ot26: 0, dt26: 0, stPay26: 0, otPay26: 0, dtPay26: 0, otDtAmt26: 0,
      };
    const year = r.ppeDate.getFullYear();
    const weekStr = formatDate(r.ppeDate);
    if (year === 2026) {
      if (week26 && weekStr !== week26) continue;
      regionMap[key].st26 += r.st;
      regionMap[key].ot26 += r.ot;
      regionMap[key].dt26 += r.dt;
      regionMap[key].stPay26 += r.stPay;
      regionMap[key].otPay26 += r.otPay;
      regionMap[key].dtPay26 += r.dtPay;
      regionMap[key].otDtAmt26 += r.otDtAmt || 0;
    } else {
      if (week25 && weekStr !== week25) continue;
      regionMap[key].st25 += r.st;
      regionMap[key].ot25 += r.ot;
      regionMap[key].dt25 += r.dt;
      regionMap[key].stPay25 += r.stPay;
      regionMap[key].otPay25 += r.otPay;
      regionMap[key].dtPay25 += r.dtPay;
      regionMap[key].otDtAmt25 += r.otDtAmt || 0;
    }
  }
  for (const code of Object.keys(REGION_NAMES)) {
    if (!regionMap[code]) {
      regionMap[code] = {
        region: code,
        st25: 0, ot25: 0, dt25: 0, stPay25: 0, otPay25: 0, dtPay25: 0, otDtAmt25: 0,
        st26: 0, ot26: 0, dt26: 0, stPay26: 0, otPay26: 0, dtPay26: 0, otDtAmt26: 0,
      };
    }
  }
  const regions = Object.values(regionMap).sort((a, b) => a.region.localeCompare(b.region));
  const totals = regions.reduce(
    (acc, g) => ({
      st25: acc.st25 + g.st25, ot25: acc.ot25 + g.ot25, dt25: acc.dt25 + g.dt25,
      st26: acc.st26 + g.st26, ot26: acc.ot26 + g.ot26, dt26: acc.dt26 + g.dt26,
      stPay25: acc.stPay25 + g.stPay25, otPay25: acc.otPay25 + g.otPay25, dtPay25: acc.dtPay25 + g.dtPay25,
      stPay26: acc.stPay26 + g.stPay26, otPay26: acc.otPay26 + g.otPay26, dtPay26: acc.dtPay26 + g.dtPay26,
      otDtAmt25: acc.otDtAmt25 + g.otDtAmt25, otDtAmt26: acc.otDtAmt26 + g.otDtAmt26,
    }),
    { st25: 0, ot25: 0, dt25: 0, st26: 0, ot26: 0, dt26: 0,
      stPay25: 0, otPay25: 0, dtPay25: 0, stPay26: 0, otPay26: 0, dtPay26: 0,
      otDtAmt25: 0, otDtAmt26: 0 }
  );
  return { regions, totals };
}

// ─── TOTAL WKS IN MONTH: MINI PIVOT WRITER ──────────────────────────────────
// Writes one pivot table at startRow. Returns next available row (after spacer).
function writeMiniPivot(sheet, startRow, title, periodLabel, regions, totals, helpers) {
  const {
    TITLE_BG, SUB_BG, SUB_TEXT, HDR_FILL, BODY_TEXT, BORDER_CLR, ALT_FILL,
    YR25, YR26, YR_DELTA, KV_TEXT, KV_FILL,
    setBorders, setOuterBorder, fmtHrs, fmtPay, fmtDeltaH, fmtDeltaP,
  } = helpers;

  let row = startRow;

  // ── Title bar ─────────────────────────────────────────────────────────────
  const titleRange = sheet.getRange(`A${row}:W${row}`);
  titleRange.merge(false);
  sheet.getRange(`A${row}`).values = [[title]];
  sheet.getRange(`A${row}`).format.font.bold = true;
  sheet.getRange(`A${row}`).format.font.size = 13;
  sheet.getRange(`A${row}`).format.font.color = "white";
  sheet.getRange(`A${row}`).format.font.name = "Segoe UI";
  titleRange.format.fill.color = TITLE_BG;
  titleRange.format.horizontalAlignment = Excel.HorizontalAlignment.center;
  titleRange.format.verticalAlignment = Excel.VerticalAlignment.center;
  titleRange.format.rowHeight = 30;
  row++;

  // ── Period label (optional — summary pivot only) ──────────────────────────
  if (periodLabel) {
    const plRange = sheet.getRange(`A${row}:W${row}`);
    plRange.merge(false);
    sheet.getRange(`A${row}`).values = [[periodLabel]];
    sheet.getRange(`A${row}`).format.font.size = 10;
    sheet.getRange(`A${row}`).format.font.italic = true;
    sheet.getRange(`A${row}`).format.font.bold = true;
    sheet.getRange(`A${row}`).format.font.color = "#FFFFFF";
    sheet.getRange(`A${row}`).format.font.name = "Segoe UI";
    sheet.getRange(`A${row}`).format.fill.color = "#0C4A6E";
    plRange.format.horizontalAlignment = Excel.HorizontalAlignment.center;
    plRange.format.verticalAlignment = Excel.VerticalAlignment.center;
    plRange.format.rowHeight = 28;
    row++;
  }

  // ── Navy divider ──────────────────────────────────────────────────────────
  sheet.getRange(`A${row}:W${row}`).format.rowHeight = 4;
  sheet.getRange(`A${row}:W${row}`).format.fill.color = TITLE_BG;
  row++;

  // ── Sub-section headers ───────────────────────────────────────────────────
  const styleSubHdr = (range, text, cell) => {
    range.merge(false);
    sheet.getRange(cell).values = [[text]];
    sheet.getRange(cell).format.font.bold = true;
    sheet.getRange(cell).format.font.size = 11;
    sheet.getRange(cell).format.font.color = SUB_TEXT;
    sheet.getRange(cell).format.font.name = "Segoe UI";
    range.format.fill.color = SUB_BG;
    range.format.horizontalAlignment = Excel.HorizontalAlignment.center;
    range.format.verticalAlignment = Excel.VerticalAlignment.center;
  };
  styleSubHdr(sheet.getRange(`A${row}:K${row}`), "HOURS BREAKDOWN BY REGION", `A${row}`);
  styleSubHdr(sheet.getRange(`M${row}:W${row}`), "PAY BREAKDOWN BY REGION", `M${row}`);
  row++;

  // ── Year group headers ────────────────────────────────────────────────────
  const styleYrHdr = (mergeRange, cell, label, bg) => {
    mergeRange.merge(false);
    sheet.getRange(cell).values = [[label]];
    mergeRange.format.font.bold = true;
    mergeRange.format.font.size = 11;
    mergeRange.format.font.color = "white";
    mergeRange.format.font.name = "Segoe UI";
    mergeRange.format.fill.color = bg;
    mergeRange.format.horizontalAlignment = Excel.HorizontalAlignment.center;
    mergeRange.format.verticalAlignment = Excel.VerticalAlignment.center;
  };
  sheet.getRange(`A${row}`).format.fill.color = HDR_FILL;
  styleYrHdr(sheet.getRange(`B${row}:D${row}`), `B${row}`, "2025", YR25);
  styleYrHdr(sheet.getRange(`E${row}:G${row}`), `E${row}`, "2026", YR26);
  styleYrHdr(sheet.getRange(`H${row}:K${row}`), `H${row}`, "\u25B3 Change", YR_DELTA);
  sheet.getRange(`M${row}`).format.fill.color = HDR_FILL;
  styleYrHdr(sheet.getRange(`N${row}:P${row}`), `N${row}`, "2025", YR25);
  styleYrHdr(sheet.getRange(`Q${row}:S${row}`), `Q${row}`, "2026", YR26);
  styleYrHdr(sheet.getRange(`T${row}:W${row}`), `T${row}`, "\u25B3 Change", YR_DELTA);
  row++;

  // ── Column headers ────────────────────────────────────────────────────────
  const styleColHdr = (range, label, bg) => {
    range.values = typeof label === "string" ? [[label]] : [label];
    range.format.font.bold = true;
    range.format.font.size = 9;
    range.format.font.color = "white";
    range.format.font.name = "Segoe UI";
    range.format.fill.color = bg;
    range.format.horizontalAlignment = Excel.HorizontalAlignment.center;
    range.format.verticalAlignment = Excel.VerticalAlignment.center;
  };
  const isSummary = periodLabel !== null;
  const hrsLabels = isSummary
    ? ["Total ST Hrs", "Total OT Hrs", "Total DT Hrs"]
    : ["ST Hrs", "OT Hrs", "DT Hrs"];
  const amtLabels = isSummary
    ? ["Total ST Amt", "Total OT Amt", "Total DT Amt"]
    : ["ST Amt", "OT Amt", "DT Amt"];
  styleColHdr(sheet.getRange(`A${row}`), "RR/DD", HDR_FILL);
  styleColHdr(sheet.getRange(`B${row}:D${row}`), hrsLabels, YR25);
  styleColHdr(sheet.getRange(`E${row}:G${row}`), hrsLabels, YR26);
  styleColHdr(sheet.getRange(`H${row}:J${row}`), ["\u25B3 ST Hrs", "\u25B3 OT Hrs", "\u25B3 DT Hrs"], YR_DELTA);
  styleColHdr(sheet.getRange(`K${row}`), "\u25B3 Total Hrs", YR_DELTA);
  styleColHdr(sheet.getRange(`M${row}`), "RR/DD", HDR_FILL);
  styleColHdr(sheet.getRange(`N${row}:P${row}`), amtLabels, YR25);
  styleColHdr(sheet.getRange(`Q${row}:S${row}`), amtLabels, YR26);
  styleColHdr(sheet.getRange(`T${row}:V${row}`), ["\u25B3 ST Amt", "\u25B3 OT Amt", "\u25B3 DT Amt"], YR_DELTA);
  styleColHdr(sheet.getRange(`W${row}`), "\u25B3 Total Amt", YR_DELTA);
  const colHdrRow = row;
  row++;

  // ── Data Rows ─────────────────────────────────────────────────────────────
  if (regions.length > 0) {
    const dataStart = row;
    const dataEnd = row + regions.length - 1;

    const hoursRows = regions.map((g) => [
      g.region, fmtHrs(g.st25), fmtHrs(g.ot25), fmtHrs(g.dt25),
      fmtHrs(g.st26), fmtHrs(g.ot26), fmtHrs(g.dt26),
      fmtDeltaH(g.st26 - g.st25), fmtDeltaH(g.ot26 - g.ot25), fmtDeltaH(g.dt26 - g.dt25),
      fmtDeltaH(g.st26 + g.ot26 + g.dt26 - (g.st25 + g.ot25 + g.dt25)),
    ]);
    const payRows = regions.map((g) => [
      g.region, fmtPay(g.stPay25), fmtPay(g.otPay25), fmtPay(g.dtPay25),
      fmtPay(g.stPay26), fmtPay(g.otPay26), fmtPay(g.dtPay26),
      fmtDeltaP(g.stPay26 - g.stPay25), fmtDeltaP(g.otPay26 - g.otPay25), fmtDeltaP(g.dtPay26 - g.dtPay25),
      fmtDeltaP(g.stPay26 + g.otPay26 + g.dtPay26 - (g.stPay25 + g.otPay25 + g.dtPay25)),
    ]);

    const textFmt = hoursRows.map(() => ["@", "@", "@", "@", "@", "@", "@", "@", "@", "@", "@"]);
    sheet.getRange(`A${dataStart}:K${dataEnd}`).numberFormat = textFmt;
    sheet.getRange(`M${dataStart}:W${dataEnd}`).numberFormat = textFmt;
    sheet.getRange(`A${dataStart}:K${dataEnd}`).values = hoursRows;
    sheet.getRange(`M${dataStart}:W${dataEnd}`).values = payRows;

    const hoursDeltaCols = ["H", "I", "J", "K"];
    const payDeltaCols = ["T", "U", "V", "W"];
    const posAddrs = [], negAddrs = [], zeroAddrs = [];

    for (let i = 0; i < regions.length; i++) {
      const bg = i % 2 === 0 ? "#FFFFFF" : ALT_FILL;
      const r = dataStart + i;
      const g = regions[i];
      const hRow = sheet.getRange(`A${r}:K${r}`);
      const pRow = sheet.getRange(`M${r}:W${r}`);
      hRow.format.fill.color = bg;
      pRow.format.fill.color = bg;
      hRow.format.font.color = BODY_TEXT;
      pRow.format.font.color = BODY_TEXT;
      hRow.format.font.size = 10;
      pRow.format.font.size = 10;
      hRow.format.font.name = "Segoe UI";
      pRow.format.font.name = "Segoe UI";
      hRow.format.rowHeight = 20;
      setBorders(hRow);
      setBorders(pRow);

      // Collect delta cell addresses by sign (hrs + pay share the same colors)
      const hDeltas = [g.st26 - g.st25, g.ot26 - g.ot25, g.dt26 - g.dt25,
        g.st26 + g.ot26 + g.dt26 - (g.st25 + g.ot25 + g.dt25)];
      hoursDeltaCols.forEach((col, idx) => {
        const a = `${col}${r}`;
        if (hDeltas[idx] > 0) posAddrs.push(a);
        else if (hDeltas[idx] < 0) negAddrs.push(a);
        else zeroAddrs.push(a);
      });
      const pDeltas = [g.stPay26 - g.stPay25, g.otPay26 - g.otPay25, g.dtPay26 - g.dtPay25,
        g.stPay26 + g.otPay26 + g.dtPay26 - (g.stPay25 + g.otPay25 + g.dtPay25)];
      payDeltaCols.forEach((col, idx) => {
        const a = `${col}${r}`;
        if (pDeltas[idx] > 0) posAddrs.push(a);
        else if (pDeltas[idx] < 0) negAddrs.push(a);
        else zeroAddrs.push(a);
      });

      // Region accent
      const aCell = sheet.getRange(`A${r}`);
      const mCell = sheet.getRange(`M${r}`);
      aCell.format.fill.color = "#E0F2FE";
      aCell.format.font.color = "#0369A1";
      aCell.format.font.bold = true;
      mCell.format.fill.color = "#E0F2FE";
      mCell.format.font.color = "#0369A1";
      mCell.format.font.bold = true;
    }

    // Apply bold + colors to all delta cells (batched before sync)
    sheet.getRange(`H${dataStart}:K${dataEnd}`).format.font.bold = true;
    sheet.getRange(`T${dataStart}:W${dataEnd}`).format.font.bold = true;
    const applyDelta = (addrs, fill, fontColor) => {
      for (const addr of addrs) {
        const cell = sheet.getRange(addr);
        cell.format.fill.color = fill;
        cell.format.font.color = fontColor;
      }
    };
    applyDelta(posAddrs, "#FFF1F2", "#E11D48");
    applyDelta(negAddrs, "#F0FDF4", "#15803D");
    applyDelta(zeroAddrs, "#F0F9FF", "#0369A1");

    // ── Totals Row ────────────────────────────────────────────────────────
    const totalRow = dataEnd + 1;
    const writeTotals = (range, vals) => {
      range.values = [vals];
      range.format.font.bold = true;
      range.format.font.size = 10;
      range.format.font.color = KV_TEXT;
      range.format.font.name = "Segoe UI";
      range.format.fill.color = KV_FILL;
      range.format.rowHeight = 24;
      setBorders(range, BORDER_CLR);
    };
    sheet.getRange(`A${totalRow}:K${totalRow}`).numberFormat = [["@","@","@","@","@","@","@","@","@","@","@"]];
    sheet.getRange(`M${totalRow}:W${totalRow}`).numberFormat = [["@","@","@","@","@","@","@","@","@","@","@"]];
    writeTotals(sheet.getRange(`A${totalRow}:K${totalRow}`), [
      "TOTAL", fmtHrs(totals.st25), fmtHrs(totals.ot25), fmtHrs(totals.dt25),
      fmtHrs(totals.st26), fmtHrs(totals.ot26), fmtHrs(totals.dt26),
      fmtDeltaH(totals.st26 - totals.st25), fmtDeltaH(totals.ot26 - totals.ot25),
      fmtDeltaH(totals.dt26 - totals.dt25),
      fmtDeltaH(totals.st26 + totals.ot26 + totals.dt26 - (totals.st25 + totals.ot25 + totals.dt25)),
    ]);
    writeTotals(sheet.getRange(`M${totalRow}:W${totalRow}`), [
      "TOTAL", fmtPay(totals.stPay25), fmtPay(totals.otPay25), fmtPay(totals.dtPay25),
      fmtPay(totals.stPay26), fmtPay(totals.otPay26), fmtPay(totals.dtPay26),
      fmtDeltaP(totals.stPay26 - totals.stPay25), fmtDeltaP(totals.otPay26 - totals.otPay25),
      fmtDeltaP(totals.dtPay26 - totals.dtPay25),
      fmtDeltaP(totals.stPay26 + totals.otPay26 + totals.dtPay26 - (totals.stPay25 + totals.otPay25 + totals.dtPay25)),
    ]);

    // Thick outer border
    setOuterBorder(sheet.getRange(`A${startRow}:K${totalRow}`));
    setOuterBorder(sheet.getRange(`M${startRow}:W${totalRow}`));
    for (const edge of ["EdgeTop"]) {
      sheet.getRange(`A${totalRow}:K${totalRow}`).format.borders.getItem(edge).style = Excel.BorderLineStyle.medium;
      sheet.getRange(`A${totalRow}:K${totalRow}`).format.borders.getItem(edge).color = "#0C4A6E";
      sheet.getRange(`M${totalRow}:W${totalRow}`).format.borders.getItem(edge).style = Excel.BorderLineStyle.medium;
      sheet.getRange(`M${totalRow}:W${totalRow}`).format.borders.getItem(edge).color = "#0C4A6E";
    }

    // Separator column L
    sheet.getRange(`L${startRow}:L${totalRow}`).format.fill.color = "#FFFFFF";

    row = totalRow + 1;
  } else {
    // No data — show message
    const noDataRange = sheet.getRange(`A${row}:W${row}`);
    noDataRange.merge(false);
    sheet.getRange(`A${row}`).values = [["No data for this week"]];
    sheet.getRange(`A${row}`).format.font.italic = true;
    sheet.getRange(`A${row}`).format.font.color = "#94A3B8";
    sheet.getRange(`A${row}`).format.font.size = 10;
    sheet.getRange(`A${row}`).format.font.name = "Segoe UI";
    noDataRange.format.horizontalAlignment = Excel.HorizontalAlignment.center;
    noDataRange.format.verticalAlignment = Excel.VerticalAlignment.center;
    noDataRange.format.rowHeight = 28;
    setOuterBorder(sheet.getRange(`A${startRow}:K${row}`));
    setOuterBorder(sheet.getRange(`M${startRow}:W${row}`));
    sheet.getRange(`L${startRow}:L${row}`).format.fill.color = "#FFFFFF";
    row++;
  }

  // Spacer row
  sheet.getRange(`A${row}:W${row}`).format.rowHeight = 12;
  return row + 1;
}

// ─── TOTAL WKS IN MONTH: MAIN SHEET WRITER ──────────────────────────────────
async function writeTotalWksSheet(context, data) {
  const SHEET_NAME = "Total Wks in Month";
  const filtered = data.filter((r) => r.role === ROLE_MECH_BASE);

  // Build month list from data
  const allDates = data.map((r) => r.ppeDate).filter(Boolean).sort((a, b) => a - b);
  const monthSet = new Set(allDates.map((d) => MONTH_NAMES[d.getMonth()]));
  const monthList = MONTH_NAMES.filter((m) => monthSet.has(m));

  if (monthList.length === 0) return;

  // Default to latest month with data
  if (!_totalWksMonth || !monthList.includes(_totalWksMonth)) {
    const latestDate = allDates[allDates.length - 1];
    _totalWksMonth = latestDate ? MONTH_NAMES[latestDate.getMonth()] : monthList[monthList.length - 1];
  }
  const monthIdx = MONTH_NAMES.indexOf(_totalWksMonth);

  // Ensure sheet exists and clear
  const sheets = context.workbook.worksheets;
  sheets.load("items/name");
  await context.sync();

  let sheet;
  const exists = sheets.items.some((s) => s.name === SHEET_NAME);
  if (exists) {
    sheet = sheets.getItem(SHEET_NAME);
    sheet.getUsedRange().clear();
  } else {
    sheet = sheets.add(SHEET_NAME);
  }

  // ── Color palette (same as MechanicBASE_Pivot) ────────────────────────────
  const TITLE_BG = "#153d64";
  const SUB_BG = "#BAE6FD";
  const SUB_TEXT = "#0C4A6E";
  const HDR_FILL = "#1E293B";
  const BODY_TEXT = "#0F172A";
  const BORDER_CLR = "#f7fcff";
  const ALT_FILL = "#F0F9FF";
  const YR25 = "#475569";
  const YR26 = "#0369A1";
  const YR_DELTA = "#0E7490";
  const KV_TEXT = "#FFFFFF";
  const KV_FILL = "#153d64";

  // Border helpers
  const setBorders = (range, color) => {
    const bc = color || BORDER_CLR;
    const b = range.format.borders;
    for (const edge of ["EdgeTop", "EdgeBottom", "EdgeLeft", "EdgeRight"]) {
      b.getItem(edge).style = Excel.BorderLineStyle.thin;
      b.getItem(edge).color = bc;
    }
    try {
      b.getItem("InsideHorizontal").style = Excel.BorderLineStyle.thin;
      b.getItem("InsideHorizontal").color = bc;
      b.getItem("InsideVertical").style = Excel.BorderLineStyle.thin;
      b.getItem("InsideVertical").color = bc;
    } catch (_) { /* single-cell */ }
  };
  const setOuterBorder = (range, color) => {
    const b = range.format.borders;
    for (const edge of ["EdgeTop", "EdgeBottom", "EdgeLeft", "EdgeRight"]) {
      b.getItem(edge).style = Excel.BorderLineStyle.medium;
      b.getItem(edge).color = color || "#0C4A6E";
    }
  };

  // Formatting helpers
  const addCommas = (n) => String(n).replace(/\B(?=(\d{3})+(?!\d))/g, ",");
  const toInt = (v) => Math.round(Number(v) || 0);
  const fmtHrs = (v) => { const n = toInt(v); return n < 0 ? `(${addCommas(Math.abs(n))})` : addCommas(n); };
  const fmtPay = (v) => { const n = toInt(v); return n < 0 ? `($${addCommas(Math.abs(n))})` : `$${addCommas(n)}`; };
  const fmtDeltaH = (v) => { const n = toInt(v); return n > 0 ? addCommas(n) : n < 0 ? `(${addCommas(Math.abs(n))})` : "-"; };
  const fmtDeltaP = (v) => { const n = toInt(v); return n > 0 ? `$${addCommas(n)}` : n < 0 ? `($${addCommas(Math.abs(n))})` : "-"; };
  const styleDelta = (cell, val) => {
    cell.format.font.bold = true;
    if (val > 0) { cell.format.fill.color = "#FFF1F2"; cell.format.font.color = "#E11D48"; }
    else if (val < 0) { cell.format.fill.color = "#F0FDF4"; cell.format.font.color = "#15803D"; }
    else { cell.format.fill.color = "#F0F9FF"; cell.format.font.color = "#0369A1"; }
  };

  const helpers = {
    TITLE_BG, SUB_BG, SUB_TEXT, HDR_FILL, BODY_TEXT, BORDER_CLR, ALT_FILL,
    YR25, YR26, YR_DELTA, KV_TEXT, KV_FILL,
    setBorders, setOuterBorder, fmtHrs, fmtPay, fmtDeltaH, fmtDeltaP, styleDelta,
  };

  // ── Row 1: Month filter bar ───────────────────────────────────────────────
  const row1 = sheet.getRange("A1:W1");
  row1.format.fill.color = "#0EA5E9";
  row1.format.rowHeight = 36;
  row1.format.verticalAlignment = Excel.VerticalAlignment.center;

  const a1 = sheet.getRange("A1");
  a1.values = [["MONTH \u229E"]];
  a1.format.font.bold = true;
  a1.format.font.size = 10;
  a1.format.font.color = "#FFFFFF";
  a1.format.font.name = "Segoe UI";
  a1.format.horizontalAlignment = Excel.HorizontalAlignment.center;

  // B1: month dropdown
  const b1 = sheet.getRange("B1");
  b1.dataValidation.clear();
  if (monthList.length > 0) {
    const aeRange = sheet.getRange(`AE1:AE${monthList.length}`);
    aeRange.numberFormat = monthList.map(() => ["@"]);
    aeRange.values = monthList.map((v) => [v]);
    b1.dataValidation.rule = { list: { inCellDropDown: true, source: `=$AE$1:$AE$${monthList.length}` } };
    b1.numberFormat = [["@"]];
    b1.values = [[_totalWksMonth]];
  } else {
    b1.values = [["No data"]];
  }
  b1.format.font.size = 11;
  b1.format.font.name = "Segoe UI";
  b1.format.font.bold = true;
  b1.format.font.color = "#0C4A6E";
  b1.format.fill.color = "#FFFFFF";
  b1.format.horizontalAlignment = Excel.HorizontalAlignment.center;
  for (const edge of ["EdgeTop", "EdgeBottom", "EdgeLeft", "EdgeRight"]) {
    b1.format.borders.getItem(edge).style = Excel.BorderLineStyle.medium;
    b1.format.borders.getItem(edge).color = "#0C4A6E";
  }

  // C1:W1: merged title
  const titleMerge = sheet.getRange("C1:W1");
  titleMerge.merge(false);
  sheet.getRange("C1").values = [["MECHANIC BASE \u2014 TOTAL WEEKS IN MONTH"]];
  sheet.getRange("C1").format.font.bold = true;
  sheet.getRange("C1").format.font.size = 12;
  sheet.getRange("C1").format.font.color = "#FFFFFF";
  sheet.getRange("C1").format.font.name = "Segoe UI";
  titleMerge.format.horizontalAlignment = Excel.HorizontalAlignment.center;

  // ── Row 2: Navy divider ───────────────────────────────────────────────────
  sheet.getRange("A2:W2").format.rowHeight = 4;
  sheet.getRange("A2:W2").format.fill.color = TITLE_BG;

  // ── Build week pairs & compute individual week data first ─────────────────
  const weekPairs = buildMonthWeekPairs(_totalWksMonth, data);
  const weekResults = weekPairs.map((pair) => ({
    pair,
    data: aggregateByRegionForMonth(
      filtered,
      pair.hasData25 ? pair.label25 : "\x00",
      pair.hasData26 ? pair.label26 : "\x00",
      monthIdx
    ),
  }));

  // ── Summary pivot = sum of individual week pivots ───────────────────────────
  const summaryMap = {};
  for (const { data: wd } of weekResults) {
    for (const g of wd.regions) {
      if (!summaryMap[g.region])
        summaryMap[g.region] = {
          region: g.region,
          st25: 0, ot25: 0, dt25: 0, stPay25: 0, otPay25: 0, dtPay25: 0, otDtAmt25: 0,
          st26: 0, ot26: 0, dt26: 0, stPay26: 0, otPay26: 0, dtPay26: 0, otDtAmt26: 0,
        };
      const s = summaryMap[g.region];
      s.st25 += g.st25; s.ot25 += g.ot25; s.dt25 += g.dt25;
      s.stPay25 += g.stPay25; s.otPay25 += g.otPay25; s.dtPay25 += g.dtPay25;
      s.otDtAmt25 += g.otDtAmt25;
      s.st26 += g.st26; s.ot26 += g.ot26; s.dt26 += g.dt26;
      s.stPay26 += g.stPay26; s.otPay26 += g.otPay26; s.dtPay26 += g.dtPay26;
      s.otDtAmt26 += g.otDtAmt26;
    }
  }
  for (const code of Object.keys(REGION_NAMES)) {
    if (!summaryMap[code]) {
      summaryMap[code] = {
        region: code,
        st25: 0, ot25: 0, dt25: 0, stPay25: 0, otPay25: 0, dtPay25: 0, otDtAmt25: 0,
        st26: 0, ot26: 0, dt26: 0, stPay26: 0, otPay26: 0, dtPay26: 0, otDtAmt26: 0,
      };
    }
  }
  const summaryRegions = Object.values(summaryMap).sort((a, b) => a.region.localeCompare(b.region));
  const summaryTotals = summaryRegions.reduce(
    (acc, g) => ({
      st25: acc.st25 + g.st25, ot25: acc.ot25 + g.ot25, dt25: acc.dt25 + g.dt25,
      st26: acc.st26 + g.st26, ot26: acc.ot26 + g.ot26, dt26: acc.dt26 + g.dt26,
      stPay25: acc.stPay25 + g.stPay25, otPay25: acc.otPay25 + g.otPay25, dtPay25: acc.dtPay25 + g.dtPay25,
      stPay26: acc.stPay26 + g.stPay26, otPay26: acc.otPay26 + g.otPay26, dtPay26: acc.dtPay26 + g.dtPay26,
      otDtAmt25: acc.otDtAmt25 + g.otDtAmt25, otDtAmt26: acc.otDtAmt26 + g.otDtAmt26,
    }),
    { st25: 0, ot25: 0, dt25: 0, st26: 0, ot26: 0, dt26: 0,
      stPay25: 0, otPay25: 0, dtPay25: 0, stPay26: 0, otPay26: 0, dtPay26: 0,
      otDtAmt25: 0, otDtAmt26: 0 }
  );

  const summaryTitle = `MECHANIC BASE \u2014 ${_totalWksMonth.toUpperCase()} MONTHLY SUMMARY`;
  const summaryPeriod = `All ${_totalWksMonth} 2025 weeks  \u25B6  All ${_totalWksMonth} 2026 weeks`;
  let nextRow = writeMiniPivot(sheet, 3, summaryTitle, summaryPeriod, summaryRegions, summaryTotals, helpers);

  // ── MTD OTDT Variance Table (right of summary, cols Y:AC) ──────────────────
  // Warm amber palette — visually distinct from the blue pivot
  const MTD_AMBER     = "#D97706";   // amber-600 — main header
  const MTD_AMBER_500 = "#F59E0B";   // amber-500 — sub-header accent
  const MTD_AMBER_900 = "#78350F";   // amber-900 — col headers / totals
  const MTD_AMBER_50  = "#FFFBEB";   // amber-50  — alt rows
  const MTD_REGION_BG = "#FEF3C7";   // amber-100 — region cell accent
  const MTD_REGION_FG = "#92400E";   // amber-800 — region cell text
  const MTD_GOAL_RED  = "#DC2626";   // red-600   — goal badge
  const MTD_VAR_POS   = "#C6EFCE";   // green bg  — positive variance
  const MTD_VAR_NEG   = "#FFC7CE";   // pink bg   — negative variance
  const MTD_VAR_POS_FG = "#006100";  // dark green text
  const MTD_VAR_NEG_FG = "#9C0006";  // dark red text

  // Row 3: Title bar (aligned with summary title row 3, inherits h=30)
  const mtdTitle = sheet.getRange("Y3:AC3");
  mtdTitle.merge(false);
  sheet.getRange("Y3").values = [["MECHANIC BASE"]];
  sheet.getRange("Y3").format.font.bold = true;
  sheet.getRange("Y3").format.font.size = 13;
  sheet.getRange("Y3").format.font.color = "white";
  sheet.getRange("Y3").format.font.name = "Segoe UI";
  mtdTitle.format.fill.color = MTD_AMBER;
  mtdTitle.format.horizontalAlignment = Excel.HorizontalAlignment.center;
  mtdTitle.format.verticalAlignment = Excel.VerticalAlignment.center;

  // Row 4: Sub-header + goal badge (aligned with summary period row 4)
  const mtdSub = sheet.getRange("Y4:AB4");
  mtdSub.merge(false);
  sheet.getRange("Y4").values = [[_totalWksMonth.toUpperCase() + " TO DATE \u2014 OTDT EXPENSE"]];
  sheet.getRange("Y4").format.font.bold = true;
  sheet.getRange("Y4").format.font.size = 10;
  sheet.getRange("Y4").format.font.color = "white";
  sheet.getRange("Y4").format.font.name = "Segoe UI";
  mtdSub.format.fill.color = MTD_AMBER_500;
  mtdSub.format.horizontalAlignment = Excel.HorizontalAlignment.center;
  mtdSub.format.verticalAlignment = Excel.VerticalAlignment.center;
  const goalCell = sheet.getRange("AC4");
  goalCell.values = [["-35% Goal"]];
  goalCell.format.font.bold = true;
  goalCell.format.font.size = 9;
  goalCell.format.font.color = "white";
  goalCell.format.font.name = "Segoe UI";
  goalCell.format.fill.color = MTD_GOAL_RED;
  goalCell.format.horizontalAlignment = Excel.HorizontalAlignment.center;
  goalCell.format.verticalAlignment = Excel.VerticalAlignment.center;

  // Row 5: Amber divider (shares row with summary navy divider, h=4)
  sheet.getRange("Y5:AC5").format.fill.color = MTD_AMBER_900;

  // Row 6: Variance analysis sub-section (aligned with summary sub-headers)
  const mtdSubLabel = sheet.getRange("Y6:AC6");
  mtdSubLabel.merge(false);
  sheet.getRange("Y6").values = [["OTDT VARIANCE ANALYSIS"]];
  sheet.getRange("Y6").format.font.bold = true;
  sheet.getRange("Y6").format.font.size = 11;
  sheet.getRange("Y6").format.font.color = MTD_REGION_FG;
  sheet.getRange("Y6").format.font.name = "Segoe UI";
  mtdSubLabel.format.fill.color = MTD_REGION_BG;
  mtdSubLabel.format.horizontalAlignment = Excel.HorizontalAlignment.center;
  mtdSubLabel.format.verticalAlignment = Excel.VerticalAlignment.center;

  // Row 7: Year group headers (aligned with summary year groups)
  sheet.getRange("Y7").format.fill.color = MTD_AMBER_900;
  const mtdYr25 = sheet.getRange("Z7");
  mtdYr25.values = [["2025"]];
  mtdYr25.format.font.bold = true;
  mtdYr25.format.font.size = 11;
  mtdYr25.format.font.color = "white";
  mtdYr25.format.font.name = "Segoe UI";
  mtdYr25.format.fill.color = YR25;
  mtdYr25.format.horizontalAlignment = Excel.HorizontalAlignment.center;
  const mtdYr26 = sheet.getRange("AA7");
  mtdYr26.values = [["2026"]];
  mtdYr26.format.font.bold = true;
  mtdYr26.format.font.size = 11;
  mtdYr26.format.font.color = "white";
  mtdYr26.format.font.name = "Segoe UI";
  mtdYr26.format.fill.color = YR26;
  mtdYr26.format.horizontalAlignment = Excel.HorizontalAlignment.center;
  const mtdChg = sheet.getRange("AB7:AC7");
  mtdChg.merge(false);
  sheet.getRange("AB7").values = [["\u25B3 Change"]];
  mtdChg.format.font.bold = true;
  mtdChg.format.font.size = 11;
  mtdChg.format.font.color = "white";
  mtdChg.format.font.name = "Segoe UI";
  mtdChg.format.fill.color = YR_DELTA;
  mtdChg.format.horizontalAlignment = Excel.HorizontalAlignment.center;

  // Row 8: Column headers (aligned with summary column headers)
  sheet.getRange("Y8:AC8").numberFormat = [["@", "@", "@", "@", "@"]];
  sheet.getRange("Y8:AC8").values = [["Region", "OTDT ($)", "OTDT ($)", "Variance", "% Change"]];
  sheet.getRange("Y8:AC8").format.font.bold = true;
  sheet.getRange("Y8:AC8").format.font.size = 9;
  sheet.getRange("Y8:AC8").format.font.color = "white";
  sheet.getRange("Y8:AC8").format.font.name = "Segoe UI";
  sheet.getRange("Y8").format.fill.color = MTD_AMBER_900;
  sheet.getRange("Z8").format.fill.color = YR25;
  sheet.getRange("AA8").format.fill.color = YR26;
  sheet.getRange("AB8:AC8").format.fill.color = YR_DELTA;
  sheet.getRange("Y8:AC8").format.horizontalAlignment = Excel.HorizontalAlignment.center;
  sheet.getRange("Y8:AC8").format.verticalAlignment = Excel.VerticalAlignment.center;
  setBorders(sheet.getRange("Y8:AC8"));

  // Data rows (row 9+) — aligned with summary pivot data rows
  const mtdVals = summaryRegions.map((g) => {
    const otdt25 = g.otDtAmt25 || 0;
    const otdt26 = g.otDtAmt26 || 0;
    const variance = otdt26 - otdt25;
    const pctChange = otdt25 !== 0 ? Math.round((variance / otdt25) * 100) : 0;
    const regionName = REGION_NAMES[g.region] || g.region;
    return { regionName, otdt25, otdt26, variance, pctChange };
  });

  if (mtdVals.length > 0) {
    const mtdDataStart = 9; // aligned with summary pivot data row 9
    const mtdDataEnd = mtdDataStart + mtdVals.length - 1;

    const mtdRows = mtdVals.map((v) => [
      v.regionName, fmtPay(v.otdt25), fmtPay(v.otdt26), fmtDeltaP(v.variance), `${v.pctChange}%`
    ]);
    sheet.getRange(`Y${mtdDataStart}:AC${mtdDataEnd}`).numberFormat = mtdVals.map(() => ["@","@","@","@","@"]);
    sheet.getRange(`Y${mtdDataStart}:AC${mtdDataEnd}`).values = mtdRows;

    for (let i = 0; i < mtdVals.length; i++) {
      const r = mtdDataStart + i;
      const v = mtdVals[i];
      const rowRange = sheet.getRange(`Y${r}:AC${r}`);
      rowRange.format.fill.color = i % 2 === 0 ? "#FFFFFF" : MTD_AMBER_50;
      rowRange.format.font.size = 10;
      rowRange.format.font.name = "Segoe UI";
      rowRange.format.rowHeight = 20;
      setBorders(rowRange);

      // Region name accent
      const regionCell = sheet.getRange(`Y${r}`);
      regionCell.format.fill.color = MTD_REGION_BG;
      regionCell.format.font.color = MTD_REGION_FG;
      regionCell.format.font.bold = true;

      // Variance & % Change coloring with font emphasis
      const varCell = sheet.getRange(`AB${r}`);
      const pctCell = sheet.getRange(`AC${r}`);
      varCell.format.font.bold = true;
      pctCell.format.font.bold = true;
      if (v.variance > 0) { varCell.format.fill.color = MTD_VAR_POS; varCell.format.font.color = MTD_VAR_POS_FG; }
      else if (v.variance < 0) { varCell.format.fill.color = MTD_VAR_NEG; varCell.format.font.color = MTD_VAR_NEG_FG; }
      if (v.pctChange > 0) { pctCell.format.fill.color = MTD_VAR_POS; pctCell.format.font.color = MTD_VAR_POS_FG; }
      else if (v.pctChange < 0) { pctCell.format.fill.color = MTD_VAR_NEG; pctCell.format.font.color = MTD_VAR_NEG_FG; }
    }

    // Totals row
    const mtdTotalRow = mtdDataEnd + 1;
    const totOtdt25 = mtdVals.reduce((s, v) => s + v.otdt25, 0);
    const totOtdt26 = mtdVals.reduce((s, v) => s + v.otdt26, 0);
    const totVar = totOtdt26 - totOtdt25;
    const totPct = totOtdt25 !== 0 ? Math.round((totVar / totOtdt25) * 100) : 0;
    sheet.getRange(`Y${mtdTotalRow}:AC${mtdTotalRow}`).numberFormat = [["@","@","@","@","@"]];
    sheet.getRange(`Y${mtdTotalRow}:AC${mtdTotalRow}`).values = [[
      "TOTAL", fmtPay(totOtdt25), fmtPay(totOtdt26), fmtDeltaP(totVar), `${totPct}%`
    ]];
    const mtdTotRange = sheet.getRange(`Y${mtdTotalRow}:AC${mtdTotalRow}`);
    mtdTotRange.format.font.bold = true;
    mtdTotRange.format.font.size = 10;
    mtdTotRange.format.font.color = "white";
    mtdTotRange.format.font.name = "Segoe UI";
    mtdTotRange.format.fill.color = MTD_AMBER_900;
    mtdTotRange.format.rowHeight = 24;
    setBorders(mtdTotRange, "#451A03");
    // Totals variance coloring
    const totVarCell = sheet.getRange(`AB${mtdTotalRow}`);
    const totPctCell = sheet.getRange(`AC${mtdTotalRow}`);
    if (totVar > 0) { totVarCell.format.fill.color = MTD_VAR_POS; totVarCell.format.font.color = MTD_VAR_POS_FG; }
    else if (totVar < 0) { totVarCell.format.fill.color = MTD_VAR_NEG; totVarCell.format.font.color = MTD_VAR_NEG_FG; }
    if (totPct > 0) { totPctCell.format.fill.color = MTD_VAR_POS; totPctCell.format.font.color = MTD_VAR_POS_FG; }
    else if (totPct < 0) { totPctCell.format.fill.color = MTD_VAR_NEG; totPctCell.format.font.color = MTD_VAR_NEG_FG; }
    // Thick border above totals
    sheet.getRange(`Y${mtdTotalRow}:AC${mtdTotalRow}`).format.borders.getItem("EdgeTop").style = Excel.BorderLineStyle.medium;
    sheet.getRange(`Y${mtdTotalRow}:AC${mtdTotalRow}`).format.borders.getItem("EdgeTop").color = "#451A03";

    // Planned Reduction lines
    const planR1 = mtdTotalRow + 1;
    const planR2 = mtdTotalRow + 2;
    sheet.getRange(`Y${planR1}:AC${planR1}`).format.fill.color = MTD_AMBER_50;
    sheet.getRange(`Y${planR1}`).values = [["Planned Reduction"]];
    sheet.getRange(`Y${planR1}`).format.font.bold = true;
    sheet.getRange(`Y${planR1}`).format.font.size = 10;
    sheet.getRange(`Y${planR1}`).format.font.name = "Segoe UI";
    sheet.getRange(`Y${planR1}`).format.font.color = MTD_REGION_FG;
    sheet.getRange(`AB${planR1}`).values = [["35%"]];
    sheet.getRange(`AB${planR1}`).format.font.bold = true;
    sheet.getRange(`AB${planR1}`).format.font.color = MTD_GOAL_RED;
    setBorders(sheet.getRange(`Y${planR1}:AC${planR1}`));
    sheet.getRange(`Y${planR2}:AC${planR2}`).format.fill.color = MTD_AMBER_50;
    sheet.getRange(`Y${planR2}`).values = [["Planned Reduction"]];
    sheet.getRange(`Y${planR2}`).format.font.bold = true;
    sheet.getRange(`Y${planR2}`).format.font.size = 10;
    sheet.getRange(`Y${planR2}`).format.font.name = "Segoe UI";
    sheet.getRange(`Y${planR2}`).format.font.color = MTD_REGION_FG;
    sheet.getRange(`AB${planR2}`).numberFormat = [["@"]];
    sheet.getRange(`AB${planR2}`).values = [[`($${addCommas(toInt(Math.abs(totOtdt25 * 0.35)))})`]];
    sheet.getRange(`AB${planR2}`).format.font.bold = true;
    sheet.getRange(`AB${planR2}`).format.font.color = MTD_GOAL_RED;
    setBorders(sheet.getRange(`Y${planR2}:AC${planR2}`));

    // Outer border around entire MTD table
    setOuterBorder(sheet.getRange(`Y3:AC${planR2}`), "#451A03");
  }

  await context.sync(); // flush summary pivot + MTD table before writing week pivots

  // ── Individual week pivots ────────────────────────────────────────────────
  for (let wi = 0; wi < weekResults.length; wi++) {
    const { pair, data: weekData } = weekResults[wi];
    const label25 = pair.label25 || "(none)";
    const label26 = pair.label26 || "(none)";
    const upcoming = !pair.hasData25 && !pair.hasData26;
    const weekTitle = upcoming
      ? `WEEK ${pair.index + 1}: ${label25} vs ${label26}  \u2014  UPCOMING`
      : `WEEK ${pair.index + 1}: ${label25} vs ${label26}`;

    nextRow = writeMiniPivot(sheet, nextRow, weekTitle, null, weekData.regions, weekData.totals, helpers);
    // Flush every 2 pivots to prevent batch overflow without excess round-trips
    if (wi % 2 === 1 || wi === weekResults.length - 1) await context.sync();
  }
  _totalWksLastRow = nextRow;

  // ── Column widths (same as MechanicBASE_Pivot) ────────────────────────────
  sheet.getRange("A:A").format.columnWidth = 14 * 5.695;
  sheet.getRange("B:K").format.columnWidth = 56;
  sheet.getRange("L:L").format.columnWidth = 8;
  sheet.getRange("M:W").format.columnWidth = 77;
  sheet.getRange("X:X").format.columnWidth = 8; // gap between pivot and MTD table
  sheet.getRange("Y:Y").format.columnWidth = 22 * 5.695;
  sheet.getRange("Z:Z").format.columnWidth = 14 * 5.695;
  sheet.getRange("AA:AA").format.columnWidth = 14 * 5.695;
  sheet.getRange("AB:AB").format.columnWidth = 16 * 5.695;
  sheet.getRange("AC:AC").format.columnWidth = 14 * 5.695;
  sheet.getRange("AE:AE").columnHidden = true;

  // ── Alignment ─────────────────────────────────────────────────────────────
  sheet.getUsedRange().format.verticalAlignment = Excel.VerticalAlignment.center;
  sheet.getRange("A:A").format.horizontalAlignment = Excel.HorizontalAlignment.center;
  sheet.getRange("M:M").format.horizontalAlignment = Excel.HorizontalAlignment.center;
  sheet.getRange("B:K").format.horizontalAlignment = Excel.HorizontalAlignment.right;
  sheet.getRange("N:W").format.horizontalAlignment = Excel.HorizontalAlignment.right;
  sheet.getRange("Z:AC").format.horizontalAlignment = Excel.HorizontalAlignment.right;

  // Re-center merged rows (row 1 title)
  titleMerge.format.horizontalAlignment = Excel.HorizontalAlignment.center;
  row1.format.horizontalAlignment = Excel.HorizontalAlignment.center;

  sheet.tabColor = TITLE_BG;
  sheet.freezePanes.freezeRows(2);

  await context.sync();
}

// ─── TOTAL WKS IN MONTH: FILTER CHANGE HANDLER ─────────────────────────────
async function handleTotalWksFilterChange(args) {
  console.log("[TotalWks] onChanged fired, raw address:", args.address, "busy:", _totalWksFilterBusy);
  if (_totalWksFilterBusy > 0) return;
  _totalWksFilterBusy++;
  try {
    const addr = (args.address || "").replace(/^[^!]+!/, "").replace(/\$/g, "").toUpperCase();
    console.log("[TotalWks] normalized addr:", addr);
    if (addr !== "B1") return;

    await Excel.run(async (context) => {
      const sheet = context.workbook.worksheets.getItem("Total Wks in Month");
      const b1 = sheet.getRange("B1");
      b1.load("values");
      await context.sync();

      const newMonth = (b1.values[0][0] || "").toString().trim();
      console.log("[TotalWks] B1 value:", JSON.stringify(newMonth), "current _totalWksMonth:", _totalWksMonth, "_totalWksLastRow:", _totalWksLastRow);
      if (!newMonth || newMonth === _totalWksMonth) return;

      _totalWksMonth = newMonth;
      await refreshTotalWksData(context, _allData); // fast path, same context
    });
  } finally {
    _totalWksFilterBusy--;
  }
}

// ─── TOTAL WKS IN MONTH: BUILDER (ENTRY POINT) ─────────────────────────────
export async function buildTotalWksInMonth(rawData) {
  _totalWksFilterBusy++;
  try {
    await Excel.run(async (context) => {
      const data = rawData || (await readRawData(context));
      await writeTotalWksSheet(context, data);

      if (!_totalWksEventRegistered) {
        const twSheet = context.workbook.worksheets.getItem("Total Wks in Month");
        twSheet.onChanged.add(handleTotalWksFilterChange);
        _totalWksEventRegistered = true;
        await context.sync();
        console.log("[TotalWks] onChanged event registered successfully");
      } else {
        console.log("[TotalWks] onChanged already registered, skipping");
      }
    });
  } finally {
    _totalWksFilterBusy--;
  }
}

// ─── TOTAL WKS IN MONTH: FAST REFRESH (filter change only) ─────────────────
// Skips static rows 1–2, col widths, alignment, freeze — saves ~60 API calls
// and 1 round-trip vs a full writeTotalWksSheet rebuild.
async function refreshTotalWksData(context, data) {
  if (_totalWksLastRow === 0) {
    await writeTotalWksSheet(context, data);
    return;
  }

  const SHEET_NAME = "Total Wks in Month";
  const sheet = context.workbook.worksheets.getItem(SHEET_NAME);

  // Update B1 value only (row 1 styling stays intact)
  const b1 = sheet.getRange("B1");
  b1.numberFormat = [["@"]];
  b1.values = [[_totalWksMonth]];

  // Clear rows 3+ (dynamic content), keeping rows 1–2 static header
  sheet.getRange(`A3:AC${_totalWksLastRow + 2}`).clear();

  const filtered = data.filter((r) => r.role === ROLE_MECH_BASE);
  const monthIdx = MONTH_NAMES.indexOf(_totalWksMonth);

  // ── Color palette ──────────────────────────────────────────────────────────
  const TITLE_BG = "#153d64";
  const SUB_BG = "#BAE6FD";
  const SUB_TEXT = "#0C4A6E";
  const HDR_FILL = "#1E293B";
  const BODY_TEXT = "#0F172A";
  const BORDER_CLR = "#f7fcff";
  const ALT_FILL = "#F0F9FF";
  const YR25 = "#475569";
  const YR26 = "#0369A1";
  const YR_DELTA = "#0E7490";
  const KV_TEXT = "#FFFFFF";
  const KV_FILL = "#153d64";

  // Border helpers
  const setBorders = (range, color) => {
    const bc = color || BORDER_CLR;
    const b = range.format.borders;
    for (const edge of ["EdgeTop", "EdgeBottom", "EdgeLeft", "EdgeRight"]) {
      b.getItem(edge).style = Excel.BorderLineStyle.thin;
      b.getItem(edge).color = bc;
    }
    try {
      b.getItem("InsideHorizontal").style = Excel.BorderLineStyle.thin;
      b.getItem("InsideHorizontal").color = bc;
      b.getItem("InsideVertical").style = Excel.BorderLineStyle.thin;
      b.getItem("InsideVertical").color = bc;
    } catch (_) { /* single-cell */ }
  };
  const setOuterBorder = (range, color) => {
    const b = range.format.borders;
    for (const edge of ["EdgeTop", "EdgeBottom", "EdgeLeft", "EdgeRight"]) {
      b.getItem(edge).style = Excel.BorderLineStyle.medium;
      b.getItem(edge).color = color || "#0C4A6E";
    }
  };

  // Formatting helpers
  const addCommas = (n) => String(n).replace(/\B(?=(\d{3})+(?!\d))/g, ",");
  const toInt = (v) => Math.round(Number(v) || 0);
  const fmtHrs = (v) => { const n = toInt(v); return n < 0 ? `(${addCommas(Math.abs(n))})` : addCommas(n); };
  const fmtPay = (v) => { const n = toInt(v); return n < 0 ? `($${addCommas(Math.abs(n))})` : `$${addCommas(n)}`; };
  const fmtDeltaH = (v) => { const n = toInt(v); return n > 0 ? addCommas(n) : n < 0 ? `(${addCommas(Math.abs(n))})` : "-"; };
  const fmtDeltaP = (v) => { const n = toInt(v); return n > 0 ? `$${addCommas(n)}` : n < 0 ? `($${addCommas(Math.abs(n))})` : "-"; };

  const helpers = {
    TITLE_BG, SUB_BG, SUB_TEXT, HDR_FILL, BODY_TEXT, BORDER_CLR, ALT_FILL,
    YR25, YR26, YR_DELTA, KV_TEXT, KV_FILL,
    setBorders, setOuterBorder, fmtHrs, fmtPay, fmtDeltaH, fmtDeltaP,
  };

  // ── Build week pairs & aggregation ─────────────────────────────────────────
  const weekPairs = buildMonthWeekPairs(_totalWksMonth, data);
  const weekResults = weekPairs.map((pair) => ({
    pair,
    data: aggregateByRegionForMonth(
      filtered,
      pair.hasData25 ? pair.label25 : "\x00",
      pair.hasData26 ? pair.label26 : "\x00",
      monthIdx
    ),
  }));

  // ── Summary pivot = sum of individual week pivots ─────────────────────────
  const summaryMap = {};
  for (const { data: wd } of weekResults) {
    for (const g of wd.regions) {
      if (!summaryMap[g.region])
        summaryMap[g.region] = {
          region: g.region,
          st25: 0, ot25: 0, dt25: 0, stPay25: 0, otPay25: 0, dtPay25: 0, otDtAmt25: 0,
          st26: 0, ot26: 0, dt26: 0, stPay26: 0, otPay26: 0, dtPay26: 0, otDtAmt26: 0,
        };
      const s = summaryMap[g.region];
      s.st25 += g.st25; s.ot25 += g.ot25; s.dt25 += g.dt25;
      s.stPay25 += g.stPay25; s.otPay25 += g.otPay25; s.dtPay25 += g.dtPay25;
      s.otDtAmt25 += g.otDtAmt25;
      s.st26 += g.st26; s.ot26 += g.ot26; s.dt26 += g.dt26;
      s.stPay26 += g.stPay26; s.otPay26 += g.otPay26; s.dtPay26 += g.dtPay26;
      s.otDtAmt26 += g.otDtAmt26;
    }
  }
  for (const code of Object.keys(REGION_NAMES)) {
    if (!summaryMap[code]) {
      summaryMap[code] = {
        region: code,
        st25: 0, ot25: 0, dt25: 0, stPay25: 0, otPay25: 0, dtPay25: 0, otDtAmt25: 0,
        st26: 0, ot26: 0, dt26: 0, stPay26: 0, otPay26: 0, dtPay26: 0, otDtAmt26: 0,
      };
    }
  }
  const summaryRegions = Object.values(summaryMap).sort((a, b) => a.region.localeCompare(b.region));
  const summaryTotals = summaryRegions.reduce(
    (acc, g) => ({
      st25: acc.st25 + g.st25, ot25: acc.ot25 + g.ot25, dt25: acc.dt25 + g.dt25,
      st26: acc.st26 + g.st26, ot26: acc.ot26 + g.ot26, dt26: acc.dt26 + g.dt26,
      stPay25: acc.stPay25 + g.stPay25, otPay25: acc.otPay25 + g.otPay25, dtPay25: acc.dtPay25 + g.dtPay25,
      stPay26: acc.stPay26 + g.stPay26, otPay26: acc.otPay26 + g.otPay26, dtPay26: acc.dtPay26 + g.dtPay26,
      otDtAmt25: acc.otDtAmt25 + g.otDtAmt25, otDtAmt26: acc.otDtAmt26 + g.otDtAmt26,
    }),
    { st25: 0, ot25: 0, dt25: 0, st26: 0, ot26: 0, dt26: 0,
      stPay25: 0, otPay25: 0, dtPay25: 0, stPay26: 0, otPay26: 0, dtPay26: 0,
      otDtAmt25: 0, otDtAmt26: 0 }
  );

  const summaryTitle = `MECHANIC BASE \u2014 ${_totalWksMonth.toUpperCase()} MONTHLY SUMMARY`;
  const summaryPeriod = `All ${_totalWksMonth} 2025 weeks  \u25B6  All ${_totalWksMonth} 2026 weeks`;
  let nextRow = writeMiniPivot(sheet, 3, summaryTitle, summaryPeriod, summaryRegions, summaryTotals, helpers);

  // ── MTD OTDT Variance Table (right of summary, cols Y:AC) ─────────────────
  const MTD_AMBER     = "#D97706";
  const MTD_AMBER_500 = "#F59E0B";
  const MTD_AMBER_900 = "#78350F";
  const MTD_AMBER_50  = "#FFFBEB";
  const MTD_REGION_BG = "#FEF3C7";
  const MTD_REGION_FG = "#92400E";
  const MTD_GOAL_RED  = "#DC2626";
  const MTD_VAR_POS   = "#C6EFCE";
  const MTD_VAR_NEG   = "#FFC7CE";
  const MTD_VAR_POS_FG = "#006100";
  const MTD_VAR_NEG_FG = "#9C0006";

  const mtdTitle = sheet.getRange("Y3:AC3");
  mtdTitle.merge(false);
  sheet.getRange("Y3").values = [["MECHANIC BASE"]];
  sheet.getRange("Y3").format.font.bold = true;
  sheet.getRange("Y3").format.font.size = 13;
  sheet.getRange("Y3").format.font.color = "white";
  sheet.getRange("Y3").format.font.name = "Segoe UI";
  mtdTitle.format.fill.color = MTD_AMBER;
  mtdTitle.format.horizontalAlignment = Excel.HorizontalAlignment.center;
  mtdTitle.format.verticalAlignment = Excel.VerticalAlignment.center;

  const mtdSub = sheet.getRange("Y4:AB4");
  mtdSub.merge(false);
  sheet.getRange("Y4").values = [[_totalWksMonth.toUpperCase() + " TO DATE \u2014 OTDT EXPENSE"]];
  sheet.getRange("Y4").format.font.bold = true;
  sheet.getRange("Y4").format.font.size = 10;
  sheet.getRange("Y4").format.font.color = "white";
  sheet.getRange("Y4").format.font.name = "Segoe UI";
  mtdSub.format.fill.color = MTD_AMBER_500;
  mtdSub.format.horizontalAlignment = Excel.HorizontalAlignment.center;
  mtdSub.format.verticalAlignment = Excel.VerticalAlignment.center;
  const goalCell = sheet.getRange("AC4");
  goalCell.values = [["-35% Goal"]];
  goalCell.format.font.bold = true;
  goalCell.format.font.size = 9;
  goalCell.format.font.color = "white";
  goalCell.format.font.name = "Segoe UI";
  goalCell.format.fill.color = MTD_GOAL_RED;
  goalCell.format.horizontalAlignment = Excel.HorizontalAlignment.center;
  goalCell.format.verticalAlignment = Excel.VerticalAlignment.center;

  sheet.getRange("Y5:AC5").format.fill.color = MTD_AMBER_900;

  const mtdSubLabel = sheet.getRange("Y6:AC6");
  mtdSubLabel.merge(false);
  sheet.getRange("Y6").values = [["OTDT VARIANCE ANALYSIS"]];
  sheet.getRange("Y6").format.font.bold = true;
  sheet.getRange("Y6").format.font.size = 11;
  sheet.getRange("Y6").format.font.color = MTD_REGION_FG;
  sheet.getRange("Y6").format.font.name = "Segoe UI";
  mtdSubLabel.format.fill.color = MTD_REGION_BG;
  mtdSubLabel.format.horizontalAlignment = Excel.HorizontalAlignment.center;
  mtdSubLabel.format.verticalAlignment = Excel.VerticalAlignment.center;

  sheet.getRange("Y7").format.fill.color = MTD_AMBER_900;
  const mtdYr25 = sheet.getRange("Z7");
  mtdYr25.values = [["2025"]];
  mtdYr25.format.font.bold = true;
  mtdYr25.format.font.size = 11;
  mtdYr25.format.font.color = "white";
  mtdYr25.format.font.name = "Segoe UI";
  mtdYr25.format.fill.color = YR25;
  mtdYr25.format.horizontalAlignment = Excel.HorizontalAlignment.center;
  const mtdYr26 = sheet.getRange("AA7");
  mtdYr26.values = [["2026"]];
  mtdYr26.format.font.bold = true;
  mtdYr26.format.font.size = 11;
  mtdYr26.format.font.color = "white";
  mtdYr26.format.font.name = "Segoe UI";
  mtdYr26.format.fill.color = YR26;
  mtdYr26.format.horizontalAlignment = Excel.HorizontalAlignment.center;
  const mtdChg = sheet.getRange("AB7:AC7");
  mtdChg.merge(false);
  sheet.getRange("AB7").values = [["\u25B3 Change"]];
  mtdChg.format.font.bold = true;
  mtdChg.format.font.size = 11;
  mtdChg.format.font.color = "white";
  mtdChg.format.font.name = "Segoe UI";
  mtdChg.format.fill.color = YR_DELTA;
  mtdChg.format.horizontalAlignment = Excel.HorizontalAlignment.center;

  sheet.getRange("Y8:AC8").numberFormat = [["@", "@", "@", "@", "@"]];
  sheet.getRange("Y8:AC8").values = [["Region", "OTDT ($)", "OTDT ($)", "Variance", "% Change"]];
  sheet.getRange("Y8:AC8").format.font.bold = true;
  sheet.getRange("Y8:AC8").format.font.size = 9;
  sheet.getRange("Y8:AC8").format.font.color = "white";
  sheet.getRange("Y8:AC8").format.font.name = "Segoe UI";
  sheet.getRange("Y8").format.fill.color = MTD_AMBER_900;
  sheet.getRange("Z8").format.fill.color = YR25;
  sheet.getRange("AA8").format.fill.color = YR26;
  sheet.getRange("AB8:AC8").format.fill.color = YR_DELTA;
  sheet.getRange("Y8:AC8").format.horizontalAlignment = Excel.HorizontalAlignment.center;
  sheet.getRange("Y8:AC8").format.verticalAlignment = Excel.VerticalAlignment.center;
  setBorders(sheet.getRange("Y8:AC8"));

  const mtdVals = summaryRegions.map((g) => {
    const otdt25 = g.otDtAmt25 || 0;
    const otdt26 = g.otDtAmt26 || 0;
    const variance = otdt26 - otdt25;
    const pctChange = otdt25 !== 0 ? Math.round((variance / otdt25) * 100) : 0;
    const regionName = REGION_NAMES[g.region] || g.region;
    return { regionName, otdt25, otdt26, variance, pctChange };
  });

  if (mtdVals.length > 0) {
    const mtdDataStart = 9;
    const mtdDataEnd = mtdDataStart + mtdVals.length - 1;
    const mtdRows = mtdVals.map((v) => [
      v.regionName, fmtPay(v.otdt25), fmtPay(v.otdt26), fmtDeltaP(v.variance), `${v.pctChange}%`
    ]);
    sheet.getRange(`Y${mtdDataStart}:AC${mtdDataEnd}`).numberFormat = mtdVals.map(() => ["@","@","@","@","@"]);
    sheet.getRange(`Y${mtdDataStart}:AC${mtdDataEnd}`).values = mtdRows;

    for (let i = 0; i < mtdVals.length; i++) {
      const r = mtdDataStart + i;
      const v = mtdVals[i];
      const rowRange = sheet.getRange(`Y${r}:AC${r}`);
      rowRange.format.fill.color = i % 2 === 0 ? "#FFFFFF" : MTD_AMBER_50;
      rowRange.format.font.size = 10;
      rowRange.format.font.name = "Segoe UI";
      rowRange.format.rowHeight = 20;
      setBorders(rowRange);

      const regionCell = sheet.getRange(`Y${r}`);
      regionCell.format.fill.color = MTD_REGION_BG;
      regionCell.format.font.color = MTD_REGION_FG;
      regionCell.format.font.bold = true;

      const varCell = sheet.getRange(`AB${r}`);
      const pctCell = sheet.getRange(`AC${r}`);
      varCell.format.font.bold = true;
      pctCell.format.font.bold = true;
      if (v.variance > 0) { varCell.format.fill.color = MTD_VAR_POS; varCell.format.font.color = MTD_VAR_POS_FG; }
      else if (v.variance < 0) { varCell.format.fill.color = MTD_VAR_NEG; varCell.format.font.color = MTD_VAR_NEG_FG; }
      if (v.pctChange > 0) { pctCell.format.fill.color = MTD_VAR_POS; pctCell.format.font.color = MTD_VAR_POS_FG; }
      else if (v.pctChange < 0) { pctCell.format.fill.color = MTD_VAR_NEG; pctCell.format.font.color = MTD_VAR_NEG_FG; }
    }

    const mtdTotalRow = mtdDataEnd + 1;
    const totOtdt25 = mtdVals.reduce((s, v) => s + v.otdt25, 0);
    const totOtdt26 = mtdVals.reduce((s, v) => s + v.otdt26, 0);
    const totVar = totOtdt26 - totOtdt25;
    const totPct = totOtdt25 !== 0 ? Math.round((totVar / totOtdt25) * 100) : 0;
    sheet.getRange(`Y${mtdTotalRow}:AC${mtdTotalRow}`).numberFormat = [["@","@","@","@","@"]];
    sheet.getRange(`Y${mtdTotalRow}:AC${mtdTotalRow}`).values = [[
      "TOTAL", fmtPay(totOtdt25), fmtPay(totOtdt26), fmtDeltaP(totVar), `${totPct}%`
    ]];
    const mtdTotRange = sheet.getRange(`Y${mtdTotalRow}:AC${mtdTotalRow}`);
    mtdTotRange.format.font.bold = true;
    mtdTotRange.format.font.size = 10;
    mtdTotRange.format.font.color = "white";
    mtdTotRange.format.font.name = "Segoe UI";
    mtdTotRange.format.fill.color = MTD_AMBER_900;
    mtdTotRange.format.rowHeight = 24;
    setBorders(mtdTotRange, "#451A03");
    const totVarCell = sheet.getRange(`AB${mtdTotalRow}`);
    const totPctCell = sheet.getRange(`AC${mtdTotalRow}`);
    if (totVar > 0) { totVarCell.format.fill.color = MTD_VAR_POS; totVarCell.format.font.color = MTD_VAR_POS_FG; }
    else if (totVar < 0) { totVarCell.format.fill.color = MTD_VAR_NEG; totVarCell.format.font.color = MTD_VAR_NEG_FG; }
    if (totPct > 0) { totPctCell.format.fill.color = MTD_VAR_POS; totPctCell.format.font.color = MTD_VAR_POS_FG; }
    else if (totPct < 0) { totPctCell.format.fill.color = MTD_VAR_NEG; totPctCell.format.font.color = MTD_VAR_NEG_FG; }
    sheet.getRange(`Y${mtdTotalRow}:AC${mtdTotalRow}`).format.borders.getItem("EdgeTop").style = Excel.BorderLineStyle.medium;
    sheet.getRange(`Y${mtdTotalRow}:AC${mtdTotalRow}`).format.borders.getItem("EdgeTop").color = "#451A03";

    const planR1 = mtdTotalRow + 1;
    const planR2 = mtdTotalRow + 2;
    sheet.getRange(`Y${planR1}:AC${planR1}`).format.fill.color = MTD_AMBER_50;
    sheet.getRange(`Y${planR1}`).values = [["Planned Reduction"]];
    sheet.getRange(`Y${planR1}`).format.font.bold = true;
    sheet.getRange(`Y${planR1}`).format.font.size = 10;
    sheet.getRange(`Y${planR1}`).format.font.name = "Segoe UI";
    sheet.getRange(`Y${planR1}`).format.font.color = MTD_REGION_FG;
    sheet.getRange(`AB${planR1}`).values = [["35%"]];
    sheet.getRange(`AB${planR1}`).format.font.bold = true;
    sheet.getRange(`AB${planR1}`).format.font.color = MTD_GOAL_RED;
    setBorders(sheet.getRange(`Y${planR1}:AC${planR1}`));
    sheet.getRange(`Y${planR2}:AC${planR2}`).format.fill.color = MTD_AMBER_50;
    sheet.getRange(`Y${planR2}`).values = [["Planned Reduction"]];
    sheet.getRange(`Y${planR2}`).format.font.bold = true;
    sheet.getRange(`Y${planR2}`).format.font.size = 10;
    sheet.getRange(`Y${planR2}`).format.font.name = "Segoe UI";
    sheet.getRange(`Y${planR2}`).format.font.color = MTD_REGION_FG;
    sheet.getRange(`AB${planR2}`).numberFormat = [["@"]];
    sheet.getRange(`AB${planR2}`).values = [[`($${addCommas(toInt(Math.abs(totOtdt25 * 0.35)))})`]];
    sheet.getRange(`AB${planR2}`).format.font.bold = true;
    sheet.getRange(`AB${planR2}`).format.font.color = MTD_GOAL_RED;
    setBorders(sheet.getRange(`Y${planR2}:AC${planR2}`));
    setOuterBorder(sheet.getRange(`Y3:AC${planR2}`), "#451A03");
  }

  await context.sync(); // flush summary pivot + MTD table

  // ── Individual week pivots ─────────────────────────────────────────────────
  for (let wi = 0; wi < weekResults.length; wi++) {
    const { pair, data: weekData } = weekResults[wi];
    const label25 = pair.label25 || "(none)";
    const label26 = pair.label26 || "(none)";
    const upcoming = !pair.hasData25 && !pair.hasData26;
    const weekTitle = upcoming
      ? `WEEK ${pair.index + 1}: ${label25} vs ${label26}  \u2014  UPCOMING`
      : `WEEK ${pair.index + 1}: ${label25} vs ${label26}`;

    nextRow = writeMiniPivot(sheet, nextRow, weekTitle, null, weekData.regions, weekData.totals, helpers);
    if (wi % 2 === 1 || wi === weekResults.length - 1) await context.sync();
  }

  // Restore vertical alignment on refreshed rows (clear() removed it)
  sheet.getRange(`A3:AC${nextRow}`).format.verticalAlignment = Excel.VerticalAlignment.center;
  _totalWksLastRow = nextRow;
  await context.sync();
}

// ─── SHARED: READ RAW DATA (batched + aggregated for large datasets) ─────────
async function readRawData(context) {
  const sheet = context.workbook.worksheets.getItem("Sheet1");
  const usedRange = sheet.getUsedRange();
  usedRange.load("rowCount,columnCount");
  await context.sync();

  const totalRows = usedRange.rowCount;
  if (totalRows < 2) return [];

  // 26 cols × 5000 rows ≈ ~2.5MB — well within Office.js ~5MB payload limit
  const BATCH = 5000;
  const numCols = Math.min(usedRange.columnCount, NUM_RAW_COLS);
  const totalBatches = Math.ceil((totalRows - 1) / BATCH);
  let skipped = 0;
  let rawRowCount = 0;

  // Aggregate on-the-fly by (region, role, name, ppeDate) to reduce memory
  // Key: "region||role||name||ppeDateTimestamp"
  const aggregated = {};

  for (let start = 1; start < totalRows; start += BATCH) {
    const batchNum = Math.floor((start - 1) / BATCH) + 1;

    // Show progress for large datasets
    if (totalRows > 10000) {
      showMessage(
        `Reading data: batch ${batchNum}/${totalBatches} (${Math.round((start / (totalRows - 1)) * 100)}%)…`
      );
    }

    const count = Math.min(BATCH, totalRows - start);
    const chunk = sheet.getRangeByIndexes(start, 0, count, numCols);
    chunk.load("values");
    await context.sync();

    const vals = chunk.values;
    for (let i = 0; i < vals.length; i++) {
      const r = vals[i];
      const role = (r[COL.ROLE] || "").toString().trim();
      if (!role) continue;

      const ppeDate = excelDateToDate(r[COL.PPE_DATE]);
      if (!ppeDate) {
        skipped++;
        continue;
      }

      rawRowCount++;
      const region = (r[COL.REGION] || "").toString().trim();
      const name = (r[COL.NAME] || "").toString().trim();
      const key = `${region}||${role}||${name}||${ppeDate.getTime()}`;

      if (!aggregated[key]) {
        aggregated[key] = {
          region,
          role,
          name,
          ppeDate,
          homeCtr: (r[COL.HOME_CTR] || "").toString().trim(),
          district: (r[COL.DISTRICT] || "").toString().trim(),
          jobDesc: (r[COL.JOB_DESC] || "").toString().trim(),
          st: 0,
          ot: 0,
          dt: 0,
          stPay: 0,
          otPay: 0,
          dtPay: 0,
          otDtHrs: 0,
          otDtAmt: 0,
        };
      }
      const agg = aggregated[key];
      agg.st += toNum(r[COL.ST]);
      agg.ot += toNum(r[COL.OT]);
      agg.dt += toNum(r[COL.DT]);
      agg.stPay += toNum(r[COL.ST_PAY]);
      agg.otPay += toNum(r[COL.OT_PAY]);
      agg.dtPay += toNum(r[COL.DT_PAY]);
      agg.otDtHrs += toNum(r[COL.OT_DT_HRS]);
      agg.otDtAmt += toNum(r[COL.OT_DT_AMT]);
    }
  }

  const result = Object.values(aggregated);

  if (skipped > 0)
    console.warn(`readRawData: skipped ${skipped} rows with missing/invalid PPE Date`);
  console.log(
    `readRawData: loaded ${rawRowCount} rows → ${result.length} aggregated entries from ${totalRows - 1} total (in ${totalBatches} batches)`
  );

  if (totalRows > 10000) {
    showMessage(
      `Loaded ${rawRowCount.toLocaleString()} rows → ${result.length.toLocaleString()} grouped entries. Processing…`
    );
  }

  return result;
}

// ─── FILTER LOGIC ─────────────────────────────────────────────────────────────
let _allData = []; // cached full dataset (Mechanic Auto excluded)

export function applyFilter(allData, filterType, filterValue) {
  // Always exclude Mechanic Auto
  const base = allData.filter((r) => r.role !== ROLE_MECH_AUTO);

  if (filterType === "All Time" || !filterValue) return base;

  return base.filter((r) => {
    const d = r.ppeDate;
    if (filterType === "Week") {
      return d.getTime() === new Date(filterValue).getTime();
    }
    if (filterType === "Month") {
      // filterValue format: "Jan 2026"
      const [mon, yr] = filterValue.split(" ");
      const monthIndex = [
        "Jan",
        "Feb",
        "Mar",
        "Apr",
        "May",
        "Jun",
        "Jul",
        "Aug",
        "Sep",
        "Oct",
        "Nov",
        "Dec",
      ].indexOf(mon);
      return d.getFullYear() === parseInt(yr, 10) && d.getMonth() === monthIndex;
    }
    if (filterType === "Year") {
      return d.getFullYear() === parseInt(filterValue, 10);
    }
    return true;
  });
}

export function populateFilterDropdowns(allData) {
  const base = allData.filter((r) => r.role !== ROLE_MECH_AUTO);
  const filterType = document.getElementById("filterType");
  const filterValue = document.getElementById("filterValue");

  const type = filterType ? filterType.value : "All Time";

  if (type === "All Time") {
    if (filterValue) filterValue.style.display = "none";
    return;
  }
  if (filterValue) filterValue.style.display = "inline-block";

  let options = [];
  if (type === "Week") {
    const dates = [...new Set(base.map((r) => r.ppeDate.getTime()))].sort((a, b) => b - a);
    options = dates.map((t) => {
      const d = new Date(t);
      return { label: formatDate(d), value: d.toISOString() };
    });
  } else if (type === "Month") {
    const months = [
      ...new Set(
        base.map((r) => {
          const d = r.ppeDate;
          return `${["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"][d.getMonth()]} ${d.getFullYear()}`;
        })
      ),
    ]
      .sort()
      .reverse();
    options = months.map((m) => ({ label: m, value: m }));
  } else if (type === "Year") {
    const years = [...new Set(base.map((r) => r.ppeDate.getFullYear()))].sort((a, b) => b - a);
    options = years.map((y) => ({ label: String(y), value: String(y) }));
  }

  if (filterValue) {
    filterValue.innerHTML = "";
    for (const opt of options) {
      const el = document.createElement("option");
      el.value = opt.value;
      el.textContent = opt.label;
      filterValue.appendChild(el);
    }
  }
}

function onFilterTypeChange() {
  populateFilterDropdowns(_allData);
  runDashboardUpdate();
}

function onFilterValueChange() {
  runDashboardUpdate();
}

function runDashboardUpdate() {
  if (!_allData || _allData.length === 0) return;
  const filterType = document.getElementById("filterType")?.value || "All Time";
  const filterValue = document.getElementById("filterValue")?.value || "";
  const filtered = applyFilter(_allData, filterType, filterValue);

  const mechBaseHours = sumHours(filtered, ROLE_MECH_BASE);
  const mechBaseExpense = sumExpense(filtered, ROLE_MECH_BASE);
  updateTaskPaneKpis({ mechBaseHours, mechBaseExpense });

  const topMech = findTopPerformer(filtered, ROLE_MECH_BASE);
  const topMechEl = document.getElementById("top-mech");
  if (topMechEl)
    topMechEl.textContent = topMech
      ? `${topMech.name} — ${Math.round(topMech.hours)} hrs`
      : "No data for this period";
}

// ─── STEP 16: REFRESH ALL ─────────────────────────────────────────────────────
export async function refreshAll() {
  setLoading(true);

  try {
    // ── Run 1: Ensure Sheet1 exists + read raw data (single round-trip) ──────
    let allData = [];
    await Excel.run(async (context) => {
      const sheets = context.workbook.worksheets;
      sheets.load("items/name");
      await context.sync();

      // Ensure Sheet1 exists
      const exists = sheets.items.some((s) => s.name === "Sheet1");
      let dataSheet;
      if (exists) {
        dataSheet = sheets.getItem("Sheet1");
      } else {
        dataSheet = sheets.add("Sheet1");
      }

      const usedRange = dataSheet.getUsedRange();
      usedRange.load("rowCount");
      await context.sync();

      if (usedRange.rowCount >= 1) {
        const headerRange = dataSheet.getRange("1:1");
        headerRange.format.font.bold = true;
        headerRange.format.fill.color = "#1F3864";
        headerRange.format.font.color = "white";
      }
      dataSheet.freezePanes.freezeRows(1);
      dataSheet.activate();

      // Read raw data in same context
      allData = await readRawData(context);
    });

    // Exclude Mechanic Auto everywhere
    _allData = allData.filter((r) => r.role !== ROLE_MECH_AUTO);

    if (_allData.length === 0) {
      showMessage("No data found. Please add rows to Sheet1.");
      setLoading(false);
      return;
    }

    // ── Run 2: Rebuild all sheets + register events (single round-trip) ──────
    _pivotFilterBusy++;
    try {
      await Excel.run(async (context) => {
        await writeProfessionalPivot(context, "MechanicBASE_Pivot", ROLE_MECH_BASE, allData);
        await writeEmpTop10Sheet(context, _allData);
        await writeMechYTDSheet(context, _allData);
        await writeMechTrendSheet(context, _allData);

        // Register pivot filter event handler (once per session)
        if (!_pivotEventRegistered) {
          const pivotSheet = context.workbook.worksheets.getItem("MechanicBASE_Pivot");
          pivotSheet.onChanged.add(handlePivotFilterChange);
          _pivotEventRegistered = true;
        }

        // Register Total Wks filter event if sheet already exists
        if (!_totalWksEventRegistered) {
          const twSheet = context.workbook.worksheets.getItemOrNullObject("Total Wks in Month");
          twSheet.load("isNullObject");
          await context.sync();
          if (!twSheet.isNullObject) {
            twSheet.onChanged.add(handleTotalWksFilterChange);
            _totalWksEventRegistered = true;
          }
        }

        await context.sync();
      });
    } finally {
      _pivotFilterBusy--;
    }

    // Populate filter dropdowns
    populateFilterDropdowns(_allData);

    // Apply current filter
    const filterType = document.getElementById("filterType")?.value || "All Time";
    const filterValue = document.getElementById("filterValue")?.value || "";
    const filtered = applyFilter(_allData, filterType, filterValue);

    // Update task pane KPIs
    const mechBaseHours = sumHours(filtered, ROLE_MECH_BASE);
    const mechBaseExpense = sumExpense(filtered, ROLE_MECH_BASE);
    updateTaskPaneKpis({ mechBaseHours, mechBaseExpense });

    // Update top performer
    const topMech = findTopPerformer(filtered, ROLE_MECH_BASE);
    const topMechEl = document.getElementById("top-mech");
    if (topMechEl)
      topMechEl.textContent = topMech
        ? `${topMech.name} — ${Math.round(topMech.hours)} hrs`
        : "No data for this period";

    showToast(`Refreshed — ${new Date().toLocaleTimeString()}`);
  } catch (err) {
    console.error("refreshAll error:", err);
    showMessage(`Error: ${err.message}`);
  } finally {
    setLoading(false);
  }
}

// ─── MECH TREND + PERIOD SHEET ───────────────────────────────────────────────
function aggregateMechTrend(rawData) {
  const filtered = rawData.filter((r) => r.role === ROLE_MECH_BASE);

  // Collect unique 2026 PPE dates
  const dates26Set = new Set();
  const dates25Set = new Set();
  for (const r of filtered) {
    if (!r.ppeDate) continue;
    if (r.ppeDate.getFullYear() === 2026) dates26Set.add(r.ppeDate.getTime());
    else dates25Set.add(r.ppeDate.getTime());
  }

  // Latest 13 weeks of 2026, ascending
  let dates26 = [...dates26Set].sort((a, b) => b - a).slice(0, 13).reverse();

  // If fewer than 13 weeks of 2026 data, backfill from latest 2025 dates
  if (dates26.length < 13) {
    const needed = 13 - dates26.length;
    const earliest26 = dates26.length > 0 ? dates26[0] : Infinity;
    const backfill = [...dates25Set]
      .filter((ts) => ts < earliest26)
      .sort((a, b) => b - a)
      .slice(0, needed)
      .reverse();
    dates26 = [...backfill, ...dates26];
  }

  // Match 2026 Saturday to its paired 2025 Saturday (end-aligned, same as buildMonthWeekPairs)
  function find2025Match(ts26) {
    const d26 = new Date(ts26);
    const monthIdx = d26.getMonth();
    const sats26 = getSaturdaysInMonth(2026, monthIdx);
    const sats25 = getSaturdaysInMonth(2025, monthIdx);
    const minLen = Math.min(sats25.length, sats26.length);
    const paired25 = sats25.slice(sats25.length - minLen);
    const paired26 = sats26.slice(sats26.length - minLen);
    const idx = paired26.findIndex(s => s.getTime() === ts26);
    if (idx === -1) return null;
    return paired25[idx].getTime();
  }

  // Pre-aggregate OT/DT Amt by (timestamp, west/east)
  const amtMap = {};
  for (const r of filtered) {
    if (!r.ppeDate || !r.region) continue;
    const ts = r.ppeDate.getTime();
    if (!amtMap[ts]) amtMap[ts] = { west: 0, east: 0 };
    const prefix = r.region.substring(0, 2);
    if (prefix === "03") amtMap[ts].west += r.otDtAmt || 0;
    else if (prefix === "07") amtMap[ts].east += r.otDtAmt || 0;
  }

  // Build 13-week result
  const weeks = [];
  for (const ts of dates26) {
    const d = new Date(ts);
    const isCurrent = d.getFullYear() === 2026;
    const label = `${MONTH_NAMES[d.getMonth()]}-${d.getDate()}-${String(d.getFullYear()).slice(2)}`;
    if (isCurrent) {
      // 2026 week: current=2026 data, prior=matched 2025 data
      const ts25 = find2025Match(ts);
      const w26 = amtMap[ts] || { west: 0, east: 0 };
      const w25 = ts25 && amtMap[ts25] ? amtMap[ts25] : { west: 0, east: 0 };
      weeks.push({
        label,
        west26: w26.west, west25: w25.west,
        east26: w26.east, east25: w25.east,
        westGoal: w25.west * 0.65, eastGoal: w25.east * 0.65,
      });
    } else {
      // Dec 2025 backfill: show as 2025 line only, no 2026 data yet
      const w = amtMap[ts] || { west: 0, east: 0 };
      weeks.push({
        label,
        west26: 0, west25: w.west,
        east26: 0, east25: w.east,
        westGoal: w.west * 0.65, eastGoal: w.east * 0.65,
      });
    }
  }
  return { weeks };
}

function aggregateRegionalTrend(rawData) {
  const filtered = rawData.filter((r) => r.role === ROLE_MECH_BASE);

  // Collect unique PPE dates across both years
  const dates26Set = new Set();
  const dates25Set = new Set();
  for (const r of filtered) {
    if (!r.ppeDate) continue;
    if (r.ppeDate.getFullYear() === 2026) dates26Set.add(r.ppeDate.getTime());
    else dates25Set.add(r.ppeDate.getTime());
  }

  // Latest 13 weeks of 2026, ascending
  let dates = [...dates26Set].sort((a, b) => b - a).slice(0, 13).reverse();

  // Backfill from 2025 if fewer than 13 weeks
  if (dates.length < 13) {
    const needed = 13 - dates.length;
    const earliest = dates.length > 0 ? dates[0] : Infinity;
    const backfill = [...dates25Set]
      .filter((ts) => ts < earliest)
      .sort((a, b) => b - a)
      .slice(0, needed)
      .reverse();
    dates = [...backfill, ...dates];
  }

  // Pre-aggregate OT/DT Amt by (timestamp, rrdd)
  const amtMap = {}; // { ts: { rrdd: amt } }
  for (const r of filtered) {
    if (!r.ppeDate || !r.region) continue;
    const ts = r.ppeDate.getTime();
    if (!amtMap[ts]) amtMap[ts] = {};
    amtMap[ts][r.region] = (amtMap[ts][r.region] || 0) + (r.otDtAmt || 0);
  }

  // Classify RRDDs into West / East / Air
  const westCodes = new Set();
  const eastCodes = new Set();
  const airCodes = new Set();
  for (const r of filtered) {
    if (!r.region) continue;
    const code = r.region;
    const prefix = code.substring(0, 2);
    if (prefix === "03" || code === "1017" || code === "1019") westCodes.add(code);
    else if (prefix === "07" || code === "1015" || code === "1021") eastCodes.add(code);
    else if (code === "2265") airCodes.add(code);
  }

  const westKeys = [...westCodes].sort();
  const eastKeys = [...eastCodes].sort();
  const airKeys = [...airCodes].sort();

  // Build week labels and per-RRDD arrays
  const weeks = [];
  const west = {};
  const east = {};
  const air = {};
  for (const k of westKeys) west[k] = [];
  for (const k of eastKeys) east[k] = [];
  for (const k of airKeys) air[k] = [];

  for (const ts of dates) {
    const d = new Date(ts);
    const label = `${MONTH_NAMES[d.getMonth()]}-${d.getDate()}-${String(d.getFullYear()).slice(2)}`;
    weeks.push({ label, ts });
    const bucket = amtMap[ts] || {};
    for (const k of westKeys) west[k].push(bucket[k] || 0);
    for (const k of eastKeys) east[k].push(bucket[k] || 0);
    for (const k of airKeys) air[k].push(bucket[k] || 0);
  }

  return { weeks, west, east, air };
}

async function writeMechTrendSheet(context, rawData) {
  const SHEET_NAME = "Mech Trend + Period";

  // Series colors
  const CLR_WEST_26   = "#1E3A8A"; // dark navy
  const CLR_WEST_25   = "#60A5FA"; // light blue
  const CLR_EAST_26   = "#DB2777"; // magenta
  const CLR_EAST_25   = "#16A34A"; // green
  const CLR_WEST_GOAL = "#FCA5A5"; // peach
  const CLR_EAST_GOAL = "#A3E635"; // lime

  // Delete existing sheet, create new
  const sheets = context.workbook.worksheets;
  sheets.load("items/name");
  await context.sync();

  const exists = sheets.items.some((s) => s.name === SHEET_NAME);
  if (exists) {
    sheets.getItem(SHEET_NAME).delete();
    await context.sync();
  }
  const sheet = sheets.add(SHEET_NAME);

  // Aggregate data
  const { weeks } = aggregateMechTrend(rawData);
  if (weeks.length === 0) {
    sheet.getRange("A1").values = [["No Mechanic BASE data available for trend chart."]];
    sheet.tabColor = "#E84B32";
    await context.sync();
    return;
  }

  // Write source data table (A1:G14)
  const numRows = weeks.length + 1; // header + data
  const headerRow = [["Week", "West 2026", "West 2025", "East 2026", "East 2025", "West (-35%) Goal", "East (-35%) Goal"]];
  const dataRows = weeks.map((w) => [w.label, w.west26, w.west25, w.east26, w.east25, w.westGoal, w.eastGoal]);
  const allRows = [...headerRow, ...dataRows];

  sheet.getRange(`A1:G${numRows}`).values = allRows;
  sheet.getRange(`A1:A${numRows}`).numberFormat = allRows.map(() => ["@"]);
  sheet.getRange(`B2:G${numRows}`).numberFormat = dataRows.map(() => ["$#,##0", "$#,##0", "$#,##0", "$#,##0", "$#,##0", "$#,##0"]);

  await context.sync();

  // Create line chart from A:G (col A = category labels, B:G = data series)
  const chartRange = sheet.getRange(`A1:G${numRows}`);
  const chart = sheet.charts.add(Excel.ChartType.line, chartRange, Excel.ChartSeriesBy.columns);
  chart.name = "MechTrendChart";
  chart.plotVisibleOnly = false;

  // Position chart below source data (wide rectangular)
  chart.setPosition(sheet.getRange("A16"), sheet.getRange("Z36"));

  // Title & axes
  chart.title.text = "MECHANICS 13-WEEK TREND (WEST vs EAST)";
  chart.title.visible = true;
  chart.axes.valueAxis.numberFormat = "$#,##0";

  // Legend
  chart.legend.visible = true;
  chart.legend.position = Excel.ChartLegendPosition.bottom;

  // Format series colors
  chart.series.load("items");
  await context.sync();

  const seriesColors = [CLR_WEST_26, CLR_WEST_25, CLR_EAST_26, CLR_EAST_25, CLR_WEST_GOAL, CLR_EAST_GOAL];
  const seriesNames  = ["West 2026", "West 2025", "East 2026", "East 2025", "West (-35%) Goal", "East (-35%) Goal"];

  for (let i = 0; i < Math.min(chart.series.items.length, 6); i++) {
    const s = chart.series.items[i];
    s.name = seriesNames[i];
    s.format.line.color = seriesColors[i];
    s.markerStyle = Excel.ChartMarkerStyle.circle;
    s.markerSize = 6;
    s.markerForegroundColor = seriesColors[i];
    s.markerBackgroundColor = seriesColors[i];
  }

  // Dashed style for goal lines
  try {
    if (chart.series.items.length >= 5) chart.series.items[4].format.line.dashStyle = "Dash";
    if (chart.series.items.length >= 6) chart.series.items[5].format.line.dashStyle = "Dash";
  } catch (_) { /* dashStyle not available in this API version */ }

  // ── Regional charts (West, East, Air) ──────────────────────────────────────
  const regional = aggregateRegionalTrend(rawData);
  const numWeeks = regional.weeks.length;
  if (numWeeks === 0) {
    sheet.getRange("A:G").columnHidden = true;
    sheet.tabColor = "#E84B32";
    sheet.freezePanes.unfreeze();
    sheet.getRange("A1").select();
    await context.sync();
    return;
  }

  const WEST_COLORS = [
    "#DC2626", "#EA580C", "#D97706", "#65A30D", "#16A34A",
    "#0D9488", "#0284C7", "#2563EB", "#7C3AED", "#C026D3", "#DB2777",
  ];
  const EAST_COLORS = [
    "#DC2626", "#EA580C", "#D97706", "#CA8A04", "#65A30D",
    "#16A34A", "#059669", "#0D9488", "#0891B2", "#0284C7",
    "#2563EB", "#4F46E5", "#7C3AED", "#C026D3", "#DB2777",
  ];
  const AIR_COLOR = "#1E3A8A";

  const weekLabels = regional.weeks.map((w) => w.label);
  const westKeys = Object.keys(regional.west).sort();
  const eastKeys = Object.keys(regional.east).sort();
  const airKeys = Object.keys(regional.air).sort();

  // Helper: write a data table starting at colOffset (1-based), return { startCol, endCol } letters
  function writeRegionalTable(rrddKeys, dataMap, colOffset) {
    const startCol = colOffset;
    // Col 1 = Week labels, Col 2+ = RRDD data
    const headerRow = ["Week", ...rrddKeys.map((k) => REGION_NAMES[k] || k)];
    const nCols = headerRow.length;
    const endCol = startCol + nCols - 1;
    const startLetter = indexToColLetter(startCol);
    const endLetter = indexToColLetter(endCol);

    // Header + data rows
    const rows = [headerRow];
    for (let w = 0; w < numWeeks; w++) {
      const row = [weekLabels[w]];
      for (const k of rrddKeys) row.push(dataMap[k][w]);
      rows.push(row);
    }

    const totalRows = rows.length;
    sheet.getRange(`${startLetter}1:${endLetter}${totalRows}`).values = rows;
    // Week column as text
    sheet.getRange(`${startLetter}1:${startLetter}${totalRows}`).numberFormat = rows.map(() => ["@"]);
    // Data columns as currency
    if (nCols > 1) {
      const dataStartLetter = indexToColLetter(startCol + 1);
      sheet.getRange(`${dataStartLetter}2:${endLetter}${totalRows}`).numberFormat =
        Array.from({ length: numWeeks }, () => Array(nCols - 1).fill("$#,##0"));
    }

    return { startLetter, endLetter, totalRows, endColIndex: endCol };
  }

  // Write regional data tables starting past column Z (col 27 = AA) so chart
  // anchor area A:Z stays visible and charts render at full width
  let nextCol = 27;
  let westTable = null;
  let eastTable = null;
  let airTable = null;

  if (westKeys.length > 0) {
    westTable = writeRegionalTable(westKeys, regional.west, nextCol);
    nextCol = westTable.endColIndex + 1;
  }
  if (eastKeys.length > 0) {
    eastTable = writeRegionalTable(eastKeys, regional.east, nextCol);
    nextCol = eastTable.endColIndex + 1;
  }
  if (airKeys.length > 0) {
    airTable = writeRegionalTable(airKeys, regional.air, nextCol);
    nextCol = airTable.endColIndex + 1;
  }

  const lastDataCol = nextCol - 1;
  await context.sync();

  // Helper: create a regional line chart
  async function createRegionalChart(tableMeta, rrddKeys, colors, chartName, chartTitle, topLeft, bottomRight) {
    const dataRange = sheet.getRange(`${tableMeta.startLetter}1:${tableMeta.endLetter}${tableMeta.totalRows}`);
    const c = sheet.charts.add(Excel.ChartType.line, dataRange, Excel.ChartSeriesBy.columns);
    c.name = chartName;
    c.plotVisibleOnly = false;
    c.setPosition(sheet.getRange(topLeft), sheet.getRange(bottomRight));
    c.title.text = chartTitle;
    c.title.visible = true;
    c.axes.valueAxis.numberFormat = "$#,##0";
    c.legend.visible = true;
    c.legend.position = Excel.ChartLegendPosition.bottom;

    c.series.load("items");
    await context.sync();

    for (let i = 0; i < Math.min(c.series.items.length, rrddKeys.length); i++) {
      const s = c.series.items[i];
      s.name = REGION_NAMES[rrddKeys[i]] || rrddKeys[i];
      s.format.line.color = colors[i % colors.length];
      s.markerStyle = Excel.ChartMarkerStyle.circle;
      s.markerSize = 6;
      s.markerForegroundColor = colors[i % colors.length];
      s.markerBackgroundColor = colors[i % colors.length];
    }
  }

  // West Region chart: A38:Z58
  if (westTable) {
    await createRegionalChart(westTable, westKeys, WEST_COLORS, "MechWestChart",
      "MECHANICS WEST REGION OTDT ($) AMT", "A38", "Z58");
  }

  // East Region chart: A60:Z80
  if (eastTable) {
    await createRegionalChart(eastTable, eastKeys, EAST_COLORS, "MechEastChart",
      "MECHANICS EAST REGION OTDT ($) AMT", "A60", "Z80");
  }

  // Air chart: A82:Z102
  if (airTable) {
    await createRegionalChart(airTable, airKeys, [AIR_COLOR], "MechAirChart",
      "MECHANICS AIR OTDT ($) AMT", "A82", "Z102");
  }

  // Hide source data columns: A:G (trend data) + AA onwards (regional data)
  // Keep H:Z visible so chart anchors render at full width
  sheet.getRange("A:G").columnHidden = true;
  if (lastDataCol >= 27) {
    const lastColLetter = indexToColLetter(lastDataCol);
    sheet.getRange(`AA:${lastColLetter}`).columnHidden = true;
  }

  // Tab color & finalize
  sheet.tabColor = "#E84B32";
  sheet.freezePanes.unfreeze();
  sheet.getRange("A1").select();

  await context.sync();
}

export async function buildMechTrend(rawData) {
  setLoading(true);
  try {
    await Excel.run(async (context) => {
      const data = rawData || (await readRawData(context));
      await writeMechTrendSheet(context, data);
    });
    showToast("Mech Trend + Period built");
  } catch (err) {
    console.error("buildMechTrend error:", err);
    showMessage(`Error: ${err.message}`);
  } finally {
    setLoading(false);
  }
}

// ─── MECH YTD SHEET ───────────────────────────────────────────────────────────
function aggregateMechYTD(rawData) {
  const filtered = rawData.filter((r) => r.role === ROLE_MECH_BASE);
  const districts = Object.keys(REGION_NAMES).sort();

  // Per-week amounts for year 26: weekAmts[month][dist][ppeDateTs] = amt (for Top 3)
  const weekAmts = {};
  for (let m = 1; m <= 12; m++) weekAmts[m] = {};

  for (const r of filtered) {
    if (!r.ppeDate || !r.region) continue;
    if (r.ppeDate.getFullYear() === 2026) {
      const m = r.ppeDate.getMonth() + 1;
      if (!weekAmts[m][r.region]) weekAmts[m][r.region] = {};
      const ts = r.ppeDate.getTime();
      weekAmts[m][r.region][ts] = (weekAmts[m][r.region][ts] || 0) + (r.otDtAmt || 0);
    }
  }

  // Compute latest-week-only amounts per month for Top 3
  const latestWeekAmts = {};
  for (let m = 1; m <= 12; m++) {
    let maxTs = 0;
    for (const dist of Object.keys(weekAmts[m])) {
      for (const ts of Object.keys(weekAmts[m][dist])) {
        if (+ts > maxTs) maxTs = +ts;
      }
    }
    if (maxTs === 0) { latestWeekAmts[m] = null; continue; }
    latestWeekAmts[m] = { date: new Date(maxTs), byDist: {} };
    for (const dist of Object.keys(weekAmts[m])) {
      latestWeekAmts[m].byDist[dist] = weekAmts[m][dist][maxTs] || 0;
    }
  }

  // Month-to-date totals — same pipeline as "Total Wks in Month" variance analysis
  const months = {};
  for (let m = 1; m <= 12; m++) {
    const monthIdx = m - 1;
    const weekPairs = buildMonthWeekPairs(MONTH_NAMES[monthIdx], rawData);
    const weekResults = weekPairs.map((pair) =>
      aggregateByRegionForMonth(
        filtered,
        pair.hasData25 ? pair.label25 : "\x00",
        pair.hasData26 ? pair.label26 : "\x00",
        monthIdx
      )
    );
    const summaryMap = {};
    for (const wd of weekResults) {
      for (const g of wd.regions) {
        if (!summaryMap[g.region]) summaryMap[g.region] = { otDtAmt25: 0, otDtAmt26: 0 };
        summaryMap[g.region].otDtAmt25 += g.otDtAmt25;
        summaryMap[g.region].otDtAmt26 += g.otDtAmt26;
      }
    }
    for (const code of districts) {
      if (!summaryMap[code]) summaryMap[code] = { otDtAmt25: 0, otDtAmt26: 0 };
    }
    months[m] = summaryMap;
  }

  return { districts, months, latestWeekAmts };
}

async function writeMechYTDSheet(context, rawData) {
  const SHEET_NAME = "Mech - YTD";
  const sheets = context.workbook.worksheets;
  sheets.load("items/name");
  await context.sync();

  let sheet;
  const exists = sheets.items.some((s) => s.name === SHEET_NAME);
  if (exists) {
    sheet = sheets.getItem(SHEET_NAME);
    sheet.getUsedRange().clear();
  } else {
    sheet = sheets.add(SHEET_NAME);
  }
  sheet.tabColor = "#E84B32";

  const { districts, months, latestWeekAmts } = aggregateMechYTD(rawData);

  const FULL_MONTH_NAMES = [
    "January", "February", "March", "April", "May", "June",
    "July", "August", "September", "October", "November", "December",
  ];
  // Seasonal quarter palette — light → medium → darker within each quarter
  const MONTH_COLORS = [
    // Q1 Amber
    { top3Bg: "#FEF3C7", top3Text: "#92400E", titleBg: "#FEF3C7", titleText: "#92400E", headerBg: "#D97706", altRow: "#FFFBEB" }, // Jan
    { top3Bg: "#FDE68A", top3Text: "#92400E", titleBg: "#FDE68A", titleText: "#78350F", headerBg: "#B45309", altRow: "#FEF3C7" }, // Feb
    { top3Bg: "#FCD34D", top3Text: "#78350F", titleBg: "#FCD34D", titleText: "#78350F", headerBg: "#92400E", altRow: "#FDE68A" }, // Mar
    // Q2 Green
    { top3Bg: "#DCFCE7", top3Text: "#14532D", titleBg: "#DCFCE7", titleText: "#14532D", headerBg: "#15803D", altRow: "#F0FDF4" }, // Apr
    { top3Bg: "#BBF7D0", top3Text: "#14532D", titleBg: "#BBF7D0", titleText: "#14532D", headerBg: "#166534", altRow: "#DCFCE7" }, // May
    { top3Bg: "#86EFAC", top3Text: "#14532D", titleBg: "#86EFAC", titleText: "#14532D", headerBg: "#14532D", altRow: "#BBF7D0" }, // Jun
    // Q3 Blue
    { top3Bg: "#DBEAFE", top3Text: "#1E3A8A", titleBg: "#DBEAFE", titleText: "#1E3A8A", headerBg: "#1D4ED8", altRow: "#EFF6FF" }, // Jul
    { top3Bg: "#BFDBFE", top3Text: "#1E3A8A", titleBg: "#BFDBFE", titleText: "#1E3A8A", headerBg: "#1E40AF", altRow: "#DBEAFE" }, // Aug
    { top3Bg: "#93C5FD", top3Text: "#1E3A8A", titleBg: "#93C5FD", titleText: "#1E3A8A", headerBg: "#1E3A8A", altRow: "#BFDBFE" }, // Sep
    // Q4 Purple
    { top3Bg: "#F3E8FF", top3Text: "#4C1D95", titleBg: "#F3E8FF", titleText: "#4C1D95", headerBg: "#7C3AED", altRow: "#FAF5FF" }, // Oct
    { top3Bg: "#E9D5FF", top3Text: "#4C1D95", titleBg: "#E9D5FF", titleText: "#4C1D95", headerBg: "#6D28D9", altRow: "#F3E8FF" }, // Nov
    { top3Bg: "#D8B4FE", top3Text: "#4C1D95", titleBg: "#D8B4FE", titleText: "#4C1D95", headerBg: "#5B21B6", altRow: "#E9D5FF" }, // Dec
  ];
  // Layout: 5 data cols + 1 separator = 6-col stride, 3 months per band (quarterly)
  // Band row structure (relative offsets):
  //  0=quarter header, 1=Top3 title, 2=WE date, 3="2026 OTDT($)", 4-6=top3 rows,
  //  7=gap, 8=big title, 9=gap, 10=col headers, 11..=district rows, last=totals
  const STRIDE = 6;
  const MONTHS_PER_BAND = 3;
  const DATA_START_REL = 11;
  const bandHeight = DATA_START_REL + districts.length + 1; // +1 totals row
  const BAND_GAP = 3;
  const QUARTER_NAMES = ["Quarter 1", "Quarter 2", "Quarter 3", "Quarter 4"];
  const QUARTER_HEADER_COLORS = [
    { bg: "#92400E", text: "#FFFFFF" }, // Q1 Amber
    { bg: "#14532D", text: "#FFFFFF" }, // Q2 Green
    { bg: "#1E3A8A", text: "#FFFFFF" }, // Q3 Blue
    { bg: "#4C1D95", text: "#FFFFFF" }, // Q4 Purple
  ];

  for (let bandIdx = 0; bandIdx < 4; bandIdx++) {
    const bandRow = bandIdx * (bandHeight + BAND_GAP); // 0-indexed absolute row

    // Quarter header — merged across all 3 month blocks
    const qHdr = sheet.getRangeByIndexes(bandRow, 0, 1, MONTHS_PER_BAND * STRIDE - 1);
    qHdr.merge();
    sheet.getRangeByIndexes(bandRow, 0, 1, 1).values = [[QUARTER_NAMES[bandIdx]]];
    qHdr.format.fill.color = QUARTER_HEADER_COLORS[bandIdx].bg;
    qHdr.format.font.color = QUARTER_HEADER_COLORS[bandIdx].text;
    qHdr.format.font.bold = true;
    qHdr.format.font.size = 14;
    qHdr.format.horizontalAlignment = Excel.HorizontalAlignment.center;
    qHdr.format.rowHeight = 30;

    for (let mi = 0; mi < MONTHS_PER_BAND; mi++) {
      const monthNum = bandIdx * MONTHS_PER_BAND + mi + 1;
      if (monthNum > 12) break;

      const colOff = mi * STRIDE; // 0-indexed absolute col of district-name col
      const mData = months[monthNum];
      const fullName = FULL_MONTH_NAMES[monthNum - 1];
      const mc = MONTH_COLORS[monthNum - 1];

      // Latest week date and per-district amounts for Top 3
      const lwk = latestWeekAmts[monthNum];
      const lastDate26 = lwk ? lwk.date : null;

      // Top 3 districts by latest-week 2026 otDtAmt (exclude Air / 2265)
      const top3 = districts
        .filter((d) => d !== "2265")
        .map((d) => ({ name: d, amt: lwk ? (lwk.byDist[d] || 0) : 0 }))
        .sort((a, b) => b.amt - a.amt)
        .slice(0, 3);

      // Helper: range by relative row offset within this band+month
      const rng = (rowRel, numCols, numRows = 1) =>
        sheet.getRangeByIndexes(bandRow + rowRel, colOff, numRows, numCols);

      // Row 1: Top 3 title
      const top3Title = rng(1, 5);
      top3Title.merge();
      sheet.getRangeByIndexes(bandRow + 1, colOff, 1, 1).values = [["Top 3 Most Help Needed"]];
      top3Title.format.fill.color = mc.top3Bg;
      top3Title.format.font.bold = true;
      top3Title.format.font.color = mc.top3Text;
      top3Title.format.horizontalAlignment = Excel.HorizontalAlignment.center;
      top3Title.format.rowHeight = 20;

      // Row 2: WE date
      const weRow = rng(2, 5);
      weRow.merge();
      sheet.getRangeByIndexes(bandRow + 2, colOff, 1, 1).values = [[lastDate26 ? `WE ${formatDate(lastDate26)}` : "WE \u2014"]];
      weRow.format.fill.color = mc.top3Bg;
      weRow.format.font.color = mc.top3Text;
      weRow.format.horizontalAlignment = Excel.HorizontalAlignment.center;
      weRow.format.rowHeight = 18;

      // Row 3: "2026 OTDT ($)" subheader
      const otdtHdr = rng(3, 5);
      otdtHdr.merge();
      sheet.getRangeByIndexes(bandRow + 3, colOff, 1, 1).values = [["2026 OTDT ($)"]];
      otdtHdr.format.fill.color = mc.top3Bg;
      otdtHdr.format.font.bold = true;
      otdtHdr.format.font.color = mc.top3Text;
      otdtHdr.format.horizontalAlignment = Excel.HorizontalAlignment.center;
      otdtHdr.format.rowHeight = 18;

      // Rows 4-6: Top 3 entries
      for (let i = 0; i < 3; i++) {
        const entry = top3[i] || { name: "\u2014", amt: 0 };
        const nameCell = sheet.getRangeByIndexes(bandRow + 4 + i, colOff, 1, 3);
        nameCell.merge();
        sheet.getRangeByIndexes(bandRow + 4 + i, colOff, 1, 1).values = [[REGION_NAMES[entry.name] || entry.name]];
        nameCell.format.rowHeight = 18;
        nameCell.format.fill.color = mc.altRow;
        const amtCell = sheet.getRangeByIndexes(bandRow + 4 + i, colOff + 3, 1, 2);
        amtCell.merge();
        sheet.getRangeByIndexes(bandRow + 4 + i, colOff + 3, 1, 1).values = [[entry.name === "\u2014" ? "" : entry.amt]];
        if (entry.name !== "\u2014") amtCell.numberFormat = [["$#,##0"]];
        amtCell.format.horizontalAlignment = Excel.HorizontalAlignment.right;
        amtCell.format.fill.color = mc.altRow;
      }

      // Row 8: Big title
      const bigTitle = rng(8, 5);
      bigTitle.merge();
      sheet.getRangeByIndexes(bandRow + 8, colOff, 1, 1).values = [[`Mechanics ${fullName} To Date`]];
      bigTitle.format.fill.color = mc.titleBg;
      bigTitle.format.font.color = mc.titleText;
      bigTitle.format.font.bold = true;
      bigTitle.format.font.size = 12;
      bigTitle.format.horizontalAlignment = Excel.HorizontalAlignment.center;
      bigTitle.format.rowHeight = 28;

      // Row 10: Column headers
      const hdr = rng(10, 5);
      hdr.values = [["District", "2025 OTDT $", "2026 OTDT $", "Var $", "Var %"]];
      hdr.format.fill.color = mc.headerBg;
      hdr.format.font.color = "#FFFFFF";
      hdr.format.font.bold = true;
      hdr.format.rowHeight = 20;
      sheet.getRangeByIndexes(bandRow + 10, colOff + 1, 1, 4).format.horizontalAlignment = Excel.HorizontalAlignment.right;

      // District data rows
      for (let di = 0; di < districts.length; di++) {
        const dist = districts[di];
        const amt25 = mData[dist] ? mData[dist].otDtAmt25 : 0;
        const amt26 = mData[dist] ? mData[dist].otDtAmt26 : 0;
        const varAmt = amt26 - amt25;
        const varPct = amt25 !== 0 ? varAmt / amt25 : amt26 !== 0 ? 1 : 0;
        const absRow = bandRow + DATA_START_REL + di;

        const dataRow = sheet.getRangeByIndexes(absRow, colOff, 1, 5);
        dataRow.values = [[REGION_NAMES[dist] || dist, amt25, amt26, varAmt, varPct]];
        dataRow.format.fill.color = di % 2 === 0 ? "#FFFFFF" : mc.altRow;
        dataRow.format.rowHeight = 18;

        sheet.getRangeByIndexes(absRow, colOff + 1, 1, 1).numberFormat = [["$#,##0"]];
        sheet.getRangeByIndexes(absRow, colOff + 2, 1, 1).numberFormat = [["$#,##0"]];
        sheet.getRangeByIndexes(absRow, colOff + 3, 1, 1).numberFormat = [["$#,##0"]];
        const pctCell = sheet.getRangeByIndexes(absRow, colOff + 4, 1, 1);
        pctCell.numberFormat = [["0%"]];
        pctCell.format.font.color = varPct < 0 ? "#DC2626" : varPct > 0 ? "#16A34A" : "#000000";
      }

      // Totals row
      const totAbsRow = bandRow + DATA_START_REL + districts.length;
      const tot25 = districts.reduce((s, d) => s + (mData[d] ? mData[d].otDtAmt25 : 0), 0);
      const tot26 = districts.reduce((s, d) => s + (mData[d] ? mData[d].otDtAmt26 : 0), 0);
      const totVar = tot26 - tot25;
      const totPct = tot25 !== 0 ? totVar / tot25 : tot26 !== 0 ? 1 : 0;

      const totRow = sheet.getRangeByIndexes(totAbsRow, colOff, 1, 5);
      totRow.values = [["Total", tot25, tot26, totVar, totPct]];
      totRow.format.fill.color = MONTH_COLORS[monthNum - 1].headerBg;
      totRow.format.font.color = "#FFFFFF";
      totRow.format.font.bold = true;
      totRow.format.rowHeight = 20;
      sheet.getRangeByIndexes(totAbsRow, colOff + 1, 1, 1).numberFormat = [["$#,##0"]];
      sheet.getRangeByIndexes(totAbsRow, colOff + 2, 1, 1).numberFormat = [["$#,##0"]];
      sheet.getRangeByIndexes(totAbsRow, colOff + 3, 1, 1).numberFormat = [["$#,##0"]];
      sheet.getRangeByIndexes(totAbsRow, colOff + 4, 1, 1).numberFormat = [["0%"]];
    }
  }

  // Column widths — applied once for all 3 month blocks per quarter
  for (let mi = 0; mi < MONTHS_PER_BAND; mi++) {
    const colOff = mi * STRIDE; // 0-indexed
    const distCol   = indexToColLetter(colOff + 1);
    const amt25Col  = indexToColLetter(colOff + 2);
    const amt26Col  = indexToColLetter(colOff + 3);
    const varAmtCol = indexToColLetter(colOff + 4);
    const varPctCol = indexToColLetter(colOff + 5);
    sheet.getRange(`${distCol}:${distCol}`).format.columnWidth   = 25 * 5.695;
    sheet.getRange(`${amt25Col}:${amt25Col}`).format.columnWidth = 13 * 5.695;
    sheet.getRange(`${amt26Col}:${amt26Col}`).format.columnWidth = 13 * 5.695;
    sheet.getRange(`${varAmtCol}:${varAmtCol}`).format.columnWidth = 11 * 5.695;
    sheet.getRange(`${varPctCol}:${varPctCol}`).format.columnWidth =  7 * 5.695;
    if (mi < MONTHS_PER_BAND - 1) {
      const sepCol = indexToColLetter(colOff + 6);
      sheet.getRange(`${sepCol}:${sepCol}`).format.columnWidth = 2 * 5.695;
    }
  }

  sheet.getUsedRange().format.verticalAlignment = Excel.VerticalAlignment.center;
  await context.sync();
}

