// ─── EMP TOP 10 ($) SHEET ────────────────────────────────────────────────────
async function writeEmpTop10Sheet(context, rawData) {
  const mechBase = rawData.filter((r) => r.role === ROLE_MECH_BASE && r.jobDesc === JOB_MAINT_JOURNEYMAN);

  // Find latest week of latest year
  const latestDate = mechBase.reduce((max, r) => (!max || r.ppeDate > max ? r.ppeDate : max), null);
  const filtered = latestDate
    ? mechBase.filter((r) => r.ppeDate.getTime() === latestDate.getTime())
    : mechBase;

  // Group by employee name — latest week only
  const empMap = {};
  for (const r of filtered) {
    const key = r.name;
    if (!empMap[key]) {
      empMap[key] = {
        name: r.name,
        otDtAmt: 0,
        otDtHrs: 0,
        district: r.district || "",
        homeCtr: r.homeCtr || "",
        jobDesc: r.jobDesc || "",
      };
    }
    empMap[key].otDtAmt += r.otDtAmt;
    empMap[key].otDtHrs += r.otDtHrs;
  }

  const top10 = Object.values(empMap)
    .sort((a, b) => b.otDtHrs - a.otDtHrs)
    .slice(0, 10);

  const sheets = context.workbook.worksheets;
  sheets.load("items/name");
  await context.sync();

  const SHEET_NAME = "Emp. Top 10 ($)";
  const TITLE_BG = "#153d64";
  const HDR_FILL = "#1E293B";
  const BODY_TEXT = "#0F172A";
  const ALT_FILL = "#F0F9FF";
  const KV_TEXT = "#FFFFFF";
  const KV_FILL = "#153d64";
  const BORDER_CLR = "#D9D9D9";

  let sheet;
  const exists = sheets.items.some((s) => s.name === SHEET_NAME);
  if (exists) {
    sheet = sheets.getItem(SHEET_NAME);
    sheet.getUsedRange().clear();
  } else {
    sheet = sheets.add(SHEET_NAME);
  }

  // ── Row 1: Title bar ──────────────────────────────────────────────────────────
  const weekLabel = latestDate ? formatDate(latestDate) : "";
  const titleText = weekLabel
    ? `Top 10 Employee Expense — Week of ${weekLabel}`
    : "Top 10 Employee Expense";
  const titleRange = sheet.getRange("A1:G1");
  titleRange.merge(false);
  sheet.getRange("A1").values = [[titleText]];
  sheet.getRange("A1").format.font.bold = true;
  sheet.getRange("A1").format.font.size = 14;
  sheet.getRange("A1").format.font.color = KV_TEXT;
  sheet.getRange("A1").format.font.name = "Segoe UI";
  titleRange.format.fill.color = TITLE_BG;
  titleRange.format.horizontalAlignment = Excel.HorizontalAlignment.center;
  titleRange.format.verticalAlignment = Excel.VerticalAlignment.center;

  // ── Row 2: Column headers ──────────────────────────────────────────────────────
  const hdrRange = sheet.getRange("A2:G2");
  hdrRange.values = [
    ["#", "Employee Name", "OT/DT Amt", "OT/DT Hrs", "RR/DD", "Cost Center", "Job Description"],
  ];
  hdrRange.format.font.bold = true;
  hdrRange.format.font.size = 10;
  hdrRange.format.font.color = KV_TEXT;
  hdrRange.format.font.name = "Segoe UI";
  hdrRange.format.fill.color = HDR_FILL;
  hdrRange.format.horizontalAlignment = Excel.HorizontalAlignment.center;
  hdrRange.format.verticalAlignment = Excel.VerticalAlignment.center;
  // Text-content headers left-aligned to match design
  sheet.getRange("B2").format.horizontalAlignment = Excel.HorizontalAlignment.left;
  sheet.getRange("E2:G2").format.horizontalAlignment = Excel.HorizontalAlignment.left;
  // Sky accent border under headers
  hdrRange.format.borders.getItem("EdgeBottom").style = Excel.BorderLineStyle.medium;
  hdrRange.format.borders.getItem("EdgeBottom").color = "#0EA5E9";

  if (top10.length === 0) {
    sheet.getRange("B3").values = [["No data"]];
    await context.sync();
    return;
  }

  const lastDataRow = 2 + top10.length;
  const totalsRow = lastDataRow + 1;

  // ── Data rows ─────────────────────────────────────────────────────────────────
  const dataRows = top10.map((e, i) => [
    i + 1,
    e.name,
    e.otDtAmt,
    e.otDtHrs,
    e.district,
    e.homeCtr,
    e.jobDesc,
  ]);
  sheet.getRange(`A3:G${lastDataRow}`).values = dataRows;
  sheet.getRange(`A3:G${lastDataRow}`).format.font.size = 10;
  sheet.getRange(`A3:G${lastDataRow}`).format.font.name = "Segoe UI";
  sheet.getRange(`A3:G${lastDataRow}`).format.font.color = BODY_TEXT;
  sheet.getRange(`A3:G${lastDataRow}`).format.verticalAlignment = Excel.VerticalAlignment.center;

  // Alternating row fill + rank medal colors
  const MEDAL = [
    { fill: "#FEF9C3", font: "#92400E" }, // gold
    { fill: "#F1F5F9", font: "#475569" }, // silver
    { fill: "#FEF3C7", font: "#78350F" }, // bronze
  ];
  for (let i = 0; i < top10.length; i++) {
    const row = 3 + i;
    const rowBg = i % 2 === 0 ? "#FFFFFF" : ALT_FILL;
    sheet.getRange(`A${row}:G${row}`).format.fill.color = rowBg;

    // Rank cell
    const rankCell = sheet.getRange(`A${row}`);
    rankCell.format.font.bold = true;
    rankCell.format.horizontalAlignment = Excel.HorizontalAlignment.center;
    if (i < 3) {
      rankCell.format.fill.color = MEDAL[i].fill;
      rankCell.format.font.color = MEDAL[i].font;
    }
  }

  // Number formats
  sheet.getRange(`C3:C${lastDataRow}`).numberFormat = [["$#,##0"]];
  sheet.getRange(`D3:D${lastDataRow}`).numberFormat = [["#,##0.00"]];

  // Column-level alignment
  sheet.getRange(`A3:A${lastDataRow}`).format.horizontalAlignment =
    Excel.HorizontalAlignment.center;
  sheet.getRange(`B3:B${lastDataRow}`).format.horizontalAlignment = Excel.HorizontalAlignment.left;
  sheet.getRange(`C3:C${lastDataRow}`).format.horizontalAlignment =
    Excel.HorizontalAlignment.center;
  sheet.getRange(`C3:C${lastDataRow}`).format.font.bold = true;
  sheet.getRange(`C3:C${lastDataRow}`).format.font.color = "#0C4A6E";
  sheet.getRange(`D3:D${lastDataRow}`).format.horizontalAlignment =
    Excel.HorizontalAlignment.center;
  sheet.getRange(`E3:E${lastDataRow}`).format.horizontalAlignment = Excel.HorizontalAlignment.left;
  sheet.getRange(`F3:F${lastDataRow}`).format.horizontalAlignment = Excel.HorizontalAlignment.left;
  sheet.getRange(`G3:G${lastDataRow}`).format.horizontalAlignment = Excel.HorizontalAlignment.left;
  sheet.getRange(`G3:G${lastDataRow}`).format.font.italic = true;
  sheet.getRange(`G3:G${lastDataRow}`).format.font.color = "#475569";

  // ── Totals row ────────────────────────────────────────────────────────────────
  const totalPay = top10.reduce((s, e) => s + e.otDtAmt, 0);
  const totalHrs = top10.reduce((s, e) => s + e.otDtHrs, 0);
  const totRange = sheet.getRange(`A${totalsRow}:G${totalsRow}`);
  totRange.values = [["", "TOTAL", totalPay, totalHrs, "", "", ""]];
  totRange.format.font.bold = true;
  totRange.format.font.size = 10;
  totRange.format.font.color = KV_TEXT;
  totRange.format.font.name = "Segoe UI";
  totRange.format.fill.color = KV_FILL;
  totRange.format.verticalAlignment = Excel.VerticalAlignment.center;
  sheet.getRange(`B${totalsRow}`).format.horizontalAlignment = Excel.HorizontalAlignment.center;
  sheet.getRange(`C${totalsRow}`).format.horizontalAlignment = Excel.HorizontalAlignment.right;
  sheet.getRange(`C${totalsRow}`).numberFormat = [["$#,##0"]];
  sheet.getRange(`D${totalsRow}`).format.horizontalAlignment = Excel.HorizontalAlignment.right;
  sheet.getRange(`D${totalsRow}`).numberFormat = [["#,##0.00"]];
  // Thick top border on totals row
  totRange.format.borders.getItem("EdgeTop").style = Excel.BorderLineStyle.medium;
  totRange.format.borders.getItem("EdgeTop").color = "#0C4A6E";

  // ── Borders ───────────────────────────────────────────────────────────────────
  // Outer border around full table (totals row is hidden — stop border at lastDataRow)
  for (const edge of ["EdgeTop", "EdgeBottom", "EdgeLeft", "EdgeRight"]) {
    sheet.getRange(`A1:G${lastDataRow}`).format.borders.getItem(edge).style =
      Excel.BorderLineStyle.medium;
    sheet.getRange(`A1:G${lastDataRow}`).format.borders.getItem(edge).color = "#0C4A6E";
  }

  // Hide totals row
  sheet.getRange(`${totalsRow}:${totalsRow}`).rowHidden = true;
  // Inner horizontal on data + header section
  try {
    sheet.getRange(`A2:G${lastDataRow}`).format.borders.getItem("InsideHorizontal").style =
      Excel.BorderLineStyle.thin;
    sheet.getRange(`A2:G${lastDataRow}`).format.borders.getItem("InsideHorizontal").color =
      BORDER_CLR;
  } catch (_) {
    /* single row — no inside borders */
  }

  // ── Column widths ─────────────────────────────────────────────────────────────
  // Column widths — values are Excel character units; converted to points (* 5.695)
  const toPoints = (chars) => chars * 5.695;
  sheet.getRange("A:A").format.columnWidth = 32; // rank — stays in points (narrow)
  sheet.getRange("B:B").format.columnWidth = toPoints(35.57); // 202.6 pt
  sheet.getRange("C:C").format.columnWidth = toPoints(14.86); //  84.6 pt
  sheet.getRange("D:D").format.columnWidth = toPoints(14.86); //  84.6 pt
  sheet.getRange("E:E").format.columnWidth = toPoints(28.29); // 161.1 pt
  sheet.getRange("F:F").format.columnWidth = toPoints(40); // 227.8 pt
  sheet.getRange("G:G").format.columnWidth = toPoints(35); // 199.3 pt

  // ── Color scale: D3:D{lastDataRow} — Red (low) → Yellow → Green (high) ───────
  const cfRange = sheet.getRange(`D3:D${lastDataRow}`);
  cfRange.conditionalFormats.clearAll();
  const cf = cfRange.conditionalFormats.add(Excel.ConditionalFormatType.colorScale);
  cf.colorScale.criteria = {
    minimum: { type: Excel.ConditionalFormatColorCriterionType.lowestValue, color: "#63BE7B" },
    midpoint: { type: Excel.ConditionalFormatColorCriterionType.percentile, value: 50, color: "#FFEB84" },
    maximum: { type: Excel.ConditionalFormatColorCriterionType.highestValue, color: "#F8696B" },
  };

  // ── Autofit all rows, then re-apply title height ───────────────────────────
  sheet.getUsedRange().format.autofitRows();
  titleRange.format.rowHeight = 36;

  sheet.tabColor = "#E84B32";
  sheet.freezePanes.freezeRows(2);

  await context.sync();
}

